
CREATE TABLE IF NOT EXISTS public.recommendation_rule_metadata (
    rule_name       text PRIMARY KEY,
    category        text NOT NULL,
    title           text NOT NULL,
    description     text,
    service_name    text,
    recommendations jsonb DEFAULT '[]'::jsonb,
    mitigations     jsonb DEFAULT '[]'::jsonb,
    compliances     jsonb DEFAULT '[]'::jsonb,
    "references"    jsonb DEFAULT '[]'::jsonb,
    created_at      timestamptz NOT NULL DEFAULT now(),
    updated_at      timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX idx_recommendation_rule_metadata_category ON public.recommendation_rule_metadata (category);

CREATE TRIGGER set_recommendation_rule_metadata_updated_at
    BEFORE UPDATE ON public.recommendation_rule_metadata
    FOR EACH ROW
    EXECUTE FUNCTION set_current_timestamp_updated_at();

-- Seed recommendation_rule_metadata with data from data.tsx
