INSERT INTO public.recommendation_rule_metadata
  (rule_name, category, title, description, service_name, recommendations, mitigations, compliances, "references")
VALUES
  ('aws_tags', 'Configuration', 'AWS Resources Should Have Tags', 'As your AWS cloud environment is becoming more and more complex, it requires better management strategies. Using a tagging schema will help you gain visibility over your cloud resources and organize them more efficiently. You can use tags for different scenarios such as tracking resources owners and their stack level, identify which resources are incurring the highest costs, and filter available resources based on particular deployment stage.', '', '["Ensure that user-defined tags (metadata) are being used for labeling, collecting, and organizing resources available within your AWS cloud environment. It is recommended that you tag your resources with appropriate metadata to help you manage and organize your resources.\n                It is recommended to have tags like Name, Environment, Owner and Role to have better track of resources."]'::jsonb, '["", "aws ec2 create-tags --resources {{recommendation.instance_id}} --tags Key=Name,Value=Prod-Web-Server Key=Role,Value=Web-Tier Key=Environment,Value=Production Key=Owner,Value=DevOps-Team", ""]'::jsonb, '["APRA", "MAS", "NIST4"]'::jsonb, '["https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/Using_Tags.html"]'::jsonb),
  ('aws_ec2_instance_auto_termination', 'Configuration', 'EC2 Instance Termination Protection Should Be Enabled', 'By default, the EBS volumes associated with the Amazon EC2 instances are deleted when these are terminated (when the DeletionOnTermination attribute value is set to true). With Termination Protection feature enabled, you have the guarantee that your EC2 instances can''t be terminated accidentally and make sure that your data remains safe.', 'AmazonEC2', '["\n        Ensure that the Amazon EC2 instances provisioned outside the Auto Scaling Groups (ASGs) have Termination Protection safety feature enabled in order to protect them from being accidentally terminated.\n        For Amazon EC2 instances provisioned manually, once the Termination Protection feature is enabled you will not be able to terminate your EC2 instances using the AWS Management Console, the AWS API, or the AWS CLI until the Termination Protection has been disabled. However, this will not prevent your instances from getting terminated if these have set the Shutdown Behavior flag to ''Terminate'' when an OS-level shutdown is performed. To make sure your EC2 instances cannot be accidentally terminated, you need to set first the instance Shutdown Behavior value to ''Stop'' (which sets the InstanceInitiatedShutdownBehavior attribute value to ''stop'') then enable Termination Protection safety feature (which sets the DisableApiTermination attribute value to true).\n        For Amazon EC2 instances provisioned automatically via AWS CloudFormation, once the Termination Protection feature is enabled, you will not be able to delete the stack containing the instance until the feature has been disabled (which sets the DisableApiTermination attribute value to false) in your CloudFormation template.\n        "]'::jsonb, '["Run modify-instance-attribute command (OSX/Linux/UNIX) using the ID of the Amazon EC2 instance that you want to protect against accidental termination as the identifier parameter, to enable the Termination Protection safety feature for the selected EC2 instance (if successful, the command does not produce an output): \n\\", "\\", "\\", "\n", "**Terraform configuration file (.tf):**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/Using_ChangingDisableAPITermination.html"]'::jsonb),
  ('aws_eks_logging', 'Configuration', 'Enable CloudTrail Logging for Kubernetes API Calls', 'Enabling CloudTrail logging for Amazon EKS clusters is vital for security monitoring, compliance adherence, incident investigation, and operational insights. It provides a detailed audit trail of API calls, enabling proactive detection of unauthorized access, ensuring regulatory compliance, facilitating incident response, and optimizing cluster performance and change management.', 'AmazonEKS', '["Ensure that CloudTrail logging is enabled for Amazon Elastic Kubernetes Service (EKS) clusters in order to record all Kubernetes API calls. Amazon CloudTrail records and documents all activities performed on EKS clusters. Whenever operations such as \"CreateCluster,\" \"ListClusters,\" or \"DeleteCluster\" are executed, corresponding records are generated in the CloudTrail trail log files. Each event or log entry includes details about the IAM identity responsible for the request and the credentials utilized."]'::jsonb, '["Update your cluster''s control plane log export configuration with the following AWS CLI command:\n        \\", "\\", "\\", "\n        "]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/eks/latest/userguide/control-plane-logs.html"]'::jsonb),
  ('aws_ecr_tag_immutable', 'Configuration', 'Ecr Image Tags should be immutable', 'ECR images should be set to IMMUTABLE to prevent code injection through image mutation. This can be done by setting image_tab_mutability to IMMUTABLE', 'AmazonECR', '["ECR images should be set to IMMUTABLE to prevent code injection through image mutation. This can be done by setting image_tab_mutability to IMMUTABLE"]'::jsonb, '["AWS CLI command to set image tag mutability to IMMUTABLE:\n\\", "\\", "\\", "\n", "**Terraform configuration file (.tf):**\n \\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonECR/latest/userguide/image-tag-mutability.html"]'::jsonb),
  ('aws_lambda_dead_letter_queue', 'Configuration', 'Enable Dead Letter Queue for Lambda Functions', 'Ensure there is a Dead Letter Queue configured for each Lambda function available in your AWS account.', 'AWSLambda', '["When an event fails all attempts or stays in the asynchronous invocation queue for too long, Amazon Lambda service discards it. Enabling Dead Letter Queues (DLQs) for your Amazon Lambda functions can make your serverless application more resilient by capturing and storing unprocessed events from asynchronous invocations for further analysis or reprocessing. Configuring Dead Letter Queues for Amazon Lambda functions will give you more control over message handling for all asynchronous invocations, including those delivered via AWS service events (S3, SNS, IoT, etc.)."]'::jsonb, '["**Terraform configuration file (.tf):**\n\\", "\\", "\\", "\n", "AWS CLI command to enable Dead Letter Queue for Lambda function:\nCreate a Dead Letter Queue (DLQ) in Amazon SQS:\n\n\\", "\\", "\\", "\n\n\n        Update the Lambda function configuration to use the Dead Letter Queue:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://aws.amazon.com/about-aws/whats-new/2016/12/aws-lambda-supports-dead-letter-queues/"]'::jsonb),
  ('aws_lambda_provisioned_concurrency', 'Configuration', 'Enable and Configure Provisioned Concurrency', 'When you are using Lambda functions for your serverless application, you are not provisioning hardware or networks, runtimes and operating systems, but you are able to enable and configure features such as provisioned concurrency which can directly affect your application''s performance. Functions configured with provisioned concurrency can execute with consistent start-up latency, making them ideal for building interactive web and mobile back-ends, latency sensitive microservices, and synchronously invoked APIs.', 'AWSLambda', '["Ensure that the Provisioned Concurrency performance feature is enabled for your Amazon Lambda functions in order to help your functions to scale without fluctuations in latency. Provisioned concurrency runs continuously and has a separate pricing plan for concurrency and execution duration."]'::jsonb, '["**Terraform configuration file (.tf):**\n\\", "\\", "\\", "\n", "AWS CLI command to enable Provisioned Concurrency for Lambda function:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/lambda/latest/dg/provisioned-concurrency.html"]'::jsonb),
  ('aws_lambda_reserved_concurrency', 'Configuration', 'Enable and Configure Reserved Concurrency For Lambda Functions', 'Reserved concurrency in Amazon Lambda allows you to set a limit on the number of concurrent executions for a specific Lambda function, ensuring it doesn''t exceed that limit even during spikes in traffic. Setting a concurrent execution limit at the Lambda function level ensures predictable scaling, prevents excessive resource usage, and enhances cost control and performance.', 'AWSLambda', '["Ensure that the Reserved Concurrency feature is enabled and configured for your Amazon Lambda functions. Enabling reserved concurrency ensures predictable performance and cost control for your Lambda functions by limiting the number of concurrent executions."]'::jsonb, '["**Terraform configuration file (.tf):**\n\\", "\\", "\\", "\n", "AWS CLI command to enable Reserved Concurrency for Lambda function:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/lambda/latest/dg/configuration-concurrency.html"]'::jsonb),
  ('aws_lambda_deprecated_runtime', 'Configuration', 'Lambda Using Supported Runtime Environment', 'When you execute your Lambda functions using a supported version of the implemented runtime environment, you ensure your function is not at risk of reaching end of support from AWS. To benefit from new features and enhancements, better security, performance and reliability, it is recommended to update to the latest environment version.', 'AWSLambda', '["Ensure that your Amazon Lambda function always uses a supported environment version, in order to avoid end of support timeframes from AWS. AWS Phase 1 Deprecation means Lambda functions no longer receive security patches or other updates to the runtime. You can no longer create functions that use the runtime, but you can continue to update existing functions. This includes updating the runtime, and rolling back to the previous runtime. Note that functions that use a deprecated runtime are no longer eligible for technical support. It is recommended to updated to the latest version to adhere to AWS cloud best practices and receive the newest software features, get the latest security patches and bug fixes, and benefit from better performance and reliability. A Lambda runtime (execution) environment is a container build based on the configuration settings that you provide when you create your Lambda function. Amazon Lambda serverless architecture supports several runtime environments such as Node.js, Edge Node.js, Java, Python and .NET Core (C#) that you can use to run your functions."]'::jsonb, '["**Terraform configuration file (.tf):**\n\\", "\\", "\\", "\n", "AWS CLI command to update the Runtime Environment Version for Lambda function:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/lambda/latest/dg/lambda-runtimes.html"]'::jsonb),
  ('aws_lambda_tracing', 'Configuration', 'Tracing Enabled for Lambda Functions', 'AWS X-Ray can provide tracing and monitoring capabilities for your Lambda functions. With active tracing mode enabled, you can save time and effort debugging and operating your functions as the X-Ray service support allows you to rapidly diagnose errors, identify bottlenecks, slowdowns and timeouts, by breaking down the latency for your Lambda functions.', 'AWSLambda', '["Ensure that active tracing is enabled for your Amazon Lambda functions in order to gain visibility into the execution and performance of the functions. With the tracing feature enabled, Amazon activates Lambda support for AWS X-Ray, a service that collects data about requests that your functions perform, which provides tools that you can use to view, filter, and gain insights into the collected data in order to identify issues and opportunities for optimization."]'::jsonb, '["**Terraform configuration file (.tf):**\n\\", "\\", "\\", "\n", "AWS CLI command to enable Active Tracing for Lambda function:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/lambda/latest/dg/services-xray.html", "https://docs.aws.amazon.com/lambda/latest/operatorguide/trace-requests.html"]'::jsonb),
  ('aws_rds_reservedinstance_configured', 'Configuration', 'Reserved Instances Should Be Configured for RDS', 'Amazon RDS Reserved Instances give you the option to reserve a DB instance for a one or three year term and in turn receive a significant discount compared to the On-Demand Instance pricing for the DB instance.
INSERT INTO public.recommendation_rule_metadata
  (rule_name, category, title, description, service_name, recommendations, mitigations, compliances, "references")
VALUES
  ('aws_elb_access_logs', 'Configuration', 'ELB Access Logs Should Be Enabled', 'Access logs capture detailed information about requests sent to your load balancer for analysis and troubleshooting.', 'AmazonELB', '["Enable access logging for your load balancer to capture request details."]'::jsonb, '["Enable access logs and configure an S3 bucket to store them."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/elasticloadbalancing/latest/classic/access-log-collection.html"]'::jsonb),
  ('aws_elb_no_listeners', 'Configuration', 'ELB Has No Listeners Configured', 'The load balancer has no listeners configured, meaning it cannot route any traffic.', 'AmazonELB', '["Configure at least one listener on the load balancer."]'::jsonb, '["Add a listener with appropriate protocol and port configuration."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/elasticloadbalancing/latest/classic/elb-listener-config.html"]'::jsonb),
  ('aws_ec2_instance_termination_protection_disabled', 'Configuration', 'EC2 Instance Termination Protection Disabled', 'The EC2 instance does not have termination protection enabled, making it vulnerable to accidental termination.', 'AmazonEC2', '["Enable termination protection for important EC2 instances."]'::jsonb, '["\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/Using_ChangingDisableAPITermination.html"]'::jsonb),
  ('aws_ec2_instance_terminates_on_os_shutdown', 'Configuration', 'EC2 Instance Terminates on OS Shutdown', 'The instance is configured to terminate when an OS-level shutdown is performed instead of stopping.', 'AmazonEC2', '["Set the instance shutdown behavior to \"stop\" instead of \"terminate\"."]'::jsonb, '["\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/terminating-instances.html#Using_ChangingInstanceInitiatedShutdownBehavior"]'::jsonb),
  ('aws_ec2_detailed_monitoring_disabled', 'Configuration', 'EC2 Detailed Monitoring Disabled', 'Detailed monitoring provides 1-minute CloudWatch metrics instead of the default 5-minute intervals.', 'AmazonEC2', '["Enable detailed monitoring for better visibility into instance performance."]'::jsonb, '["\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/using-cloudwatch-new.html"]'::jsonb),
  ('aws_route53_query_logging_disabled', 'Configuration', 'Route 53 Query Logging Disabled', 'DNS query logging is not enabled for this hosted zone.', 'AmazonRoute53', '["Enable query logging to monitor DNS queries for troubleshooting and security analysis."]'::jsonb, '["Create a query logging configuration for the hosted zone."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/Route53/latest/DeveloperGuide/query-logs.html"]'::jsonb),
  ('aws_route53_dnssec_disabled', 'Configuration', 'Route 53 DNSSEC Not Enabled', 'DNSSEC signing is not enabled for this hosted zone, leaving it vulnerable to DNS spoofing attacks.', 'AmazonRoute53', '["Enable DNSSEC signing to protect against DNS spoofing and cache poisoning attacks."]'::jsonb, '["Enable DNSSEC signing in the Route 53 console or CLI."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/Route53/latest/DeveloperGuide/domain-configure-dnssec.html"]'::jsonb),
  ('aws_route53_empty_hosted_zone', 'Configuration', 'Route 53 Empty Hosted Zone', 'The hosted zone has no record sets beyond the default NS and SOA records.', 'AmazonRoute53', '["Review if this hosted zone is needed. Empty hosted zones incur costs."]'::jsonb, '["Delete the hosted zone if it is no longer needed, or add appropriate DNS records."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/Route53/latest/DeveloperGuide/hosted-zones-working-with.html"]'::jsonb),
  ('aws_route53_unhealthy_health_check', 'Configuration', 'Route 53 Unhealthy Health Check', 'A Route 53 health check is reporting an unhealthy status.', 'AmazonRoute53', '["Investigate and resolve the unhealthy health check to ensure proper DNS failover."]'::jsonb, '["Check the target endpoint health and update the health check configuration if needed."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/Route53/latest/DeveloperGuide/health-checks-types.html"]'::jsonb),
  ('aws_route53_health_check_no_alarm', 'Configuration', 'Route 53 Health Check Has No CloudWatch Alarm', 'The health check does not have a CloudWatch alarm configured for failure notifications.', 'AmazonRoute53', '["Create a CloudWatch alarm for the health check to receive notifications on failures."]'::jsonb, '["HealthCheckStatus"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/Route53/latest/DeveloperGuide/health-checks-monitor-view-status.html"]'::jsonb),
  ('aws_stepfunctions_high_failure_rate', 'Configuration', 'Step Functions High Failure Rate', 'The Step Functions state machine has a high execution failure rate.', 'AWSStepFunctions', '["Investigate the root cause of failures and implement error handling."]'::jsonb, '["Add Catch and Retry blocks to handle transient failures in your state machine definition."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/step-functions/latest/dg/concepts-error-handling.html"]'::jsonb),
  ('aws_stepfunctions_logging_disabled', 'Configuration', 'Step Functions Logging Disabled', 'Logging is disabled for this state machine, making it difficult to troubleshoot execution issues.', 'AWSStepFunctions', '["Enable CloudWatch Logs for the state machine to track execution details."]'::jsonb, '["Update the state machine to include a logging configuration with a CloudWatch Logs log group."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/step-functions/latest/dg/cw-logs.html"]'::jsonb),
  ('aws_stepfunctions_logging_not_configured', 'Configuration', 'Step Functions Logging Not Configured', 'The state machine does not have a logging configuration defined.', 'AWSStepFunctions', '["Configure logging for the state machine."]'::jsonb, '["Add a logging configuration with appropriate log level (ALL, ERROR, or FATAL)."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/step-functions/latest/dg/cw-logs.html"]'::jsonb),
  ('aws_stepfunctions_xray_tracing_disabled', 'Configuration', 'Step Functions X-Ray Tracing Disabled', 'X-Ray tracing is not enabled for this state machine.', 'AWSStepFunctions', '["Enable X-Ray tracing to gain insights into execution performance and bottlenecks."]'::jsonb, '["Update the state machine to enable X-Ray tracing."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/step-functions/latest/dg/concepts-xray-tracing.html"]'::jsonb),
  ('aws_stepfunctions_express_not_utilized', 'Configuration', 'Step Functions Express Workflow Not Utilized', 'The state machine could benefit from using Express Workflows for high-volume, short-duration executions.', 'AWSStepFunctions', '["Consider using Express Workflows for workloads with high execution rates and short durations."]'::jsonb, '["Create a new Express state machine if the workload pattern is suitable."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/step-functions/latest/dg/concepts-standard-vs-express.html"]'::jsonb),
  ('aws_stepfunctions_large_definition', 'Configuration', 'Step Functions Large State Machine Definition', 'The state machine definition is unusually large, which may indicate it should be broken into smaller machines.', 'AWSStepFunctions', '["Consider breaking large state machines into smaller, composable state machines."]'::jsonb, '["Refactor the state machine into nested workflows or separate state machines."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/step-functions/latest/dg/limits-overview.html"]'::jsonb),
  ('aws_msk_enhanced_monitoring', 'Configuration', 'MSK Enhanced Monitoring Should Be Enabled', 'Enhanced monitoring provides additional broker-level metrics for better visibility into cluster performance.', 'AmazonMSK', '["Enable enhanced monitoring for your MSK cluster."]'::jsonb, '["Update the cluster to use PER_BROKER or PER_TOPIC_PER_BROKER monitoring level."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/msk/latest/developerguide/monitoring.html"]'::jsonb),
  ('aws_msk_cloudwatch_logs', 'Configuration', 'MSK CloudWatch Logs Should Be Enabled', 'Broker logs should be sent to CloudWatch Logs for monitoring and troubleshooting.', 'AmazonMSK', '["Enable CloudWatch Logs for MSK broker logs."]'::jsonb, '["Update the cluster logging configuration to enable CloudWatch Logs."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/msk/latest/developerguide/msk-logging.html"]'::jsonb),
  ('aws_cfn_drift_detection_check', 'Configuration', 'CloudFormation Drift Detection Check', 'CloudFormation stack drift should be checked regularly to detect manual changes to managed resources.', 'AWSCloudFormation', '["Run drift detection periodically to identify resources that have been modified outside of CloudFormation."]'::jsonb, '["\n**Run drift detection:**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AWSCloudFormation/latest/UserGuide/using-cfn-stack-drift.html"]'::jsonb),
  ('aws_cfn_stack_drifted', 'Configuration', 'CloudFormation Stack Has Drifted', 'The CloudFormation stack has drifted from its template, meaning resources have been modified outside of CloudFormation.', 'AWSCloudFormation', '["Resolve drift by updating the template or reverting manual changes."]'::jsonb, '["Update the stack to match the current template or import the drifted resources."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AWSCloudFormation/latest/UserGuide/using-cfn-stack-drift.html"]'::jsonb),
  ('aws_cfn_termination_protection', 'Configuration', 'CloudFormation Termination Protection Should Be Enabled', 'Termination protection prevents the stack from being accidentally deleted.', 'AWSCloudFormation', '["Enable termination protection for important CloudFormation stacks."]'::jsonb, '["\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AWSCloudFormation/latest/UserGuide/using-cfn-protect-stacks.html"]'::jsonb),
  ('aws_cfn_stack_policy', 'Configuration', 'CloudFormation Stack Policy Should Be Configured', 'A stack policy prevents unintentional updates to stack resources.', 'AWSCloudFormation', '["Set a stack policy to protect critical resources from unintentional updates."]'::jsonb, '["aws cloudformation set-stack-policy --stack-name {{resource_name}} --stack-policy-body file://policy.json"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AWSCloudFormation/latest/UserGuide/protect-stack-resources.html"]'::jsonb),
  ('aws_cloudtrail_multi_region', 'Configuration', 'CloudTrail Multi-Region Logging Should Be Enabled', 'CloudTrail should be configured to log events from all AWS regions.', 'AWSCloudTrail', '["Enable multi-region logging to capture API activity across all regions."]'::jsonb, '["\n**Update the trail to enable multi-region:**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/awscloudtrail/latest/userguide/receive-cloudtrail-log-files-from-multiple-regions.html"]'::jsonb),
  ('aws_cloudtrail_log_validation', 'Configuration', 'CloudTrail Log File Validation Should Be Enabled', 'Log file validation ensures that CloudTrail log files have not been tampered with after delivery.', 'AWSCloudTrail', '["Enable log file validation to detect unauthorized modifications to log files."]'::jsonb, '["\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/awscloudtrail/latest/userguide/cloudtrail-log-file-validation-intro.html"]'::jsonb),
  ('aws_cloudtrail_cloudwatch_integration', 'Configuration', 'CloudTrail Should Be Integrated with CloudWatch', 'Integrating CloudTrail with CloudWatch Logs enables real-time monitoring of API activity.', 'AWSCloudTrail', '["Configure CloudTrail to send logs to a CloudWatch Logs group for real-time monitoring and alerting."]'::jsonb, '["Update the trail to specify a CloudWatch Logs log group and IAM role."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/awscloudtrail/latest/userguide/send-cloudtrail-events-to-cloudwatch-logs.html"]'::jsonb),
  ('aws_cloudtrail_logging_enabled', 'Configuration', 'CloudTrail Logging Should Be Enabled', 'CloudTrail logging is not enabled, meaning API calls are not being recorded.', 'AWSCloudTrail', '["Enable CloudTrail logging to record API calls for security and compliance."]'::jsonb, '["\n**Start logging:**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/awscloudtrail/latest/userguide/cloudtrail-turning-off-logging.html"]'::jsonb),
  ('aws_cloudtrail_eds_retention', 'Configuration', 'CloudTrail Event Data Store Retention Period', 'The CloudTrail Event Data Store retention period should be configured appropriately.', 'AWSCloudTrail', '["Set an appropriate retention period for the event data store based on compliance requirements."]'::jsonb, '["Update the event data store retention period."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/awscloudtrail/latest/userguide/query-event-data-store.html"]'::jsonb),
  ('aws_cloudtrail_no_multi_region_trail', 'Configuration', 'No Multi-Region CloudTrail Trail Exists', 'No multi-region trail is configured, meaning API activity may not be captured in all regions.', 'AWSCloudTrail', '["Create a multi-region trail to capture API calls across all AWS regions."]'::jsonb, '["aws cloudtrail create-trail --name {{resource_name}} --s3-bucket-name my-bucket --is-multi-region-trail"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/awscloudtrail/latest/userguide/receive-cloudtrail-log-files-from-multiple-regions.html"]'::jsonb),
  ('aws_dynamodb_pitr_enabled', 'Configuration', 'DynamoDB Point-in-Time Recovery Should Be Enabled', 'Point-in-time recovery provides continuous backups of your DynamoDB table data.', 'AmazonDynamoDB', '["Enable point-in-time recovery to protect against accidental data loss."]'::jsonb, '["aws dynamodb update-continuous-backups --table-name {{resource_name}} --point-in-time-recovery-specification PointInTimeRecoveryEnabled=true"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/PointInTimeRecovery.html"]'::jsonb),
  ('aws_elasticbeanstalk_single_instance', 'Configuration', 'Elastic Beanstalk Single Instance Environment', 'The environment is running on a single instance without load balancing, which is not suitable for production workloads.', 'AWSElasticBeanstalk', '["Use a load-balanced environment for production workloads to ensure high availability."]'::jsonb, '["Rebuild the environment with a load-balanced configuration."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/elasticbeanstalk/latest/dg/using-features-managing-env-types.html"]'::jsonb),
  ('aws_elasticbeanstalk_enhanced_health_disabled', 'Configuration', 'Elastic Beanstalk Enhanced Health Reporting Disabled', 'Enhanced health reporting provides detailed health information about instances and the environment.', 'AWSElasticBeanstalk', '["Enable enhanced health reporting for better visibility into environment health."]'::jsonb, '["Update the environment to enable enhanced health reporting in the configuration."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/elasticbeanstalk/latest/dg/health-enhanced.html"]'::jsonb),
  ('aws_codeartifact_repository_policy', 'Configuration', 'CodeArtifact Repository Policy Should Be Configured', 'The CodeArtifact repository does not have a resource policy configured to control access.', 'AWSCodeArtifact', '["Configure a resource policy on the repository to control access."]'::jsonb, '["Set a repository permissions policy using the AWS CLI or console."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/codeartifact/latest/ug/repo-policies.html"]'::jsonb),
  ('aws_cloudwatch_log_group_retention', 'Configuration', 'CloudWatch Log Group Retention Should Be Configured', 'Log groups without a retention policy will retain logs indefinitely, increasing storage costs.', 'AmazonCloudWatch', '["Set a retention period for CloudWatch log groups to manage costs."]'::jsonb, '["\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonCloudWatch/latest/logs/Working-with-log-groups-and-streams.html"]'::jsonb),
  ('aws_backup_plan_rule_lifecycle', 'Configuration', 'Backup Plan Rule Lifecycle Should Be Configured', 'The backup plan rule does not have a lifecycle configuration for transitioning or expiring backups.', 'AWSBackup', '["Configure lifecycle rules to transition backups to cold storage and expire old backups."]'::jsonb, '["Update the backup plan rule to include lifecycle settings."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/aws-backup/latest/devguide/creating-a-backup-plan.html"]'::jsonb),
  ('aws_backup_plan_has_rules', 'Configuration', 'Backup Plan Should Have Rules', 'The backup plan does not have any backup rules configured.', 'AWSBackup', '["Add at least one backup rule to the backup plan."]'::jsonb, '["Update the backup plan to include backup rules with appropriate schedules."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/aws-backup/latest/devguide/creating-a-backup-plan.html"]'::jsonb),
  ('aws_cloudfront_access_logging', 'Configuration', 'CloudFront Access Logging Should Be Enabled', 'Access logging provides detailed information about every user request that CloudFront receives.', 'AmazonCloudFront', '["Enable access logging for your CloudFront distribution."]'::jsonb, '["Update the distribution to enable logging and specify an S3 bucket for log storage."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/AccessLogs.html"]'::jsonb),
  ('aws_cloudfront_geo_restriction', 'Configuration', 'CloudFront Geo-Restriction Should Be Configured', 'Geo-restriction allows you to control which countries can access your content.', 'AmazonCloudFront', '["Configure geo-restrictions if your content should only be accessible from specific countries."]'::jsonb, '["Update the distribution to add geo-restriction rules."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/georestrictions.html"]'::jsonb),
