  ('azure_vmss_automatic_os_upgrade_disabled', 'Configuration', 'VMSS Automatic OS Upgrade Disabled', 'Automatic OS image upgrades are not enabled for this VM Scale Set. Without automatic upgrades, VMSS instances may run outdated OS images with known vulnerabilities.', 'AzureVMSS', '["Enable automatic OS upgrades to keep instances up to date."]'::jsonb, '["Enable the automatic OS upgrade policy on the scale set."]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machine-scale-sets/virtual-machine-scale-sets-automatic-upgrade"]'::jsonb),
