  ('azure_policy_assignment_not_enforced', 'Configuration', 'Azure Policy Assignment Not Enforced', 'The policy assignment enforcement mode is set to DoNotEnforce.', 'AzurePolicy', '["Set the enforcement mode to Default for production environments."]'::jsonb, '["Update the policy assignment enforcement mode."]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/governance/policy/concepts/assignment-structure"]'::jsonb),
