  ('azure_arc_machine_disconnected', 'Configuration', 'Azure Arc Machine Disconnected', 'The Azure Arc-enabled machine is disconnected from Azure.', 'AzureArc', '["Investigate why the machine is disconnected and restore connectivity."]'::jsonb, '["Check the Azure Connected Machine agent status on the machine."]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-arc/servers/troubleshoot-agent-onboard"]'::jsonb),
  ('azure_arc_outdated_agent', 'Configuration', 'Azure Arc Agent Outdated', 'The Azure Connected Machine agent is not the latest version.', 'AzureArc', '["Update the agent to the latest version."]'::jsonb, '["Update the agent using the built-in update mechanism."]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-arc/servers/manage-agent"]'::jsonb),
  ('azure_arc_machine_stale_status', 'Configuration', 'Azure Arc Machine Has Stale Status', 'The Azure Arc-enabled machine has not reported its status recently. This may indicate network connectivity issues, agent problems, or that the machine has been decommissioned.', 'AzureArc', '["Investigate the machine connectivity and agent health."]'::jsonb, '["Check the machine network connectivity and restart the agent if needed."]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-arc/servers/manage-agent"]'::jsonb),
  ('aws_ecr_public_tag_immutable', 'Configuration', 'ECR Public Repository Image Tags Should Be Immutable', 'Amazon ECR Public repository image tags should be configured as immutable to prevent image tags from being overwritten. Immutable tags ensure that each image tag uniquely identifies a specific image version, preventing supply chain attacks through tag manipulation.', 'AmazonECR', '["Enable image tag immutability for all ECR Public repositories to prevent image tags from being overwritten. This ensures that once an image is pushed with a specific tag, the tag cannot be reassigned to a different image digest."]'::jsonb, '["Update the ECR Public repository to enable image tag immutability:\n\\", "\\", "\\", "\n\nAlternatively, recreate the repository with immutable tags enabled:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://docs.aws.amazon.com/AmazonECR/latest/public/public-repository-edit.html"]'::jsonb),
  ('aws_ecs_service_autoscaling_disabled', 'Configuration', 'ECS Service Auto Scaling Should Be Enabled', 'Amazon ECS services should have auto scaling configured to automatically adjust the desired count of tasks in response to demand changes. Without auto scaling, services cannot dynamically respond to traffic patterns, potentially leading to over-provisioning (wasted cost) or under-provisioning (degraded performance).', 'AmazonECS', '["Configure Application Auto Scaling for the ECS service to automatically adjust task count based on CloudWatch metrics such as CPU utilization, memory utilization, or custom metrics. Set appropriate minimum and maximum capacity limits."]'::jsonb, '["Register the ECS service as a scalable target and create a scaling policy:\n\\", "\\", "\\", ""]'::jsonb, '["APRA", "MAS"]'::jsonb, '["https://docs.aws.amazon.com/AmazonECS/latest/developerguide/service-auto-scaling.html"]'::jsonb),
  ('azure_activity_log_alert_broad_scope', 'Configuration', 'Azure Activity Log Alert Has Overly Broad Scope', 'The Activity Log Alert is scoped to the entire subscription rather than specific resource groups, which may generate excessive noise.', 'ActivityLogAlerts', '["The Activity Log Alert is scoped to the entire subscription rather than specific resource groups, which may generate excessive noise."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/alerts-activity-log"]'::jsonb),
  ('azure_activity_log_alert_disabled', 'Configuration', 'Azure Activity Log Alert Is Disabled', 'An Activity Log Alert is disabled and will not trigger notifications for matching events.', 'ActivityLogAlerts', '["An Activity Log Alert is disabled and will not trigger notifications for matching events."]'::jsonb, '["Enable Activity Log Alert through the Azure Portal or using Azure CLI/Terraform. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/alerts-activity-log"]'::jsonb),
  ('azure_activity_log_alert_empty_condition', 'Configuration', 'Azure Activity Log Alert Has Empty Condition', 'The Activity Log Alert has no conditions configured, making it ineffective at filtering events.', 'ActivityLogAlerts', '["The Activity Log Alert has no conditions configured, making it ineffective at filtering events."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/alerts-activity-log"]'::jsonb),
  ('azure_activity_log_alert_missing_tags', 'Configuration', 'Azure Activity Log Alert Should Have Tags', 'The Activity Log Alert has no tags for organization and cost tracking.', 'ActivityLogAlerts', '["The Activity Log Alert has no tags for organization and cost tracking."]'::jsonb, '["Configure Activity Log Alert Tags through the Azure Portal or using Azure CLI. Refer to the documentation link below for detailed configuration steps."]'::jsonb, '["APRA", "MAS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-resource-manager/management/tag-resources"]'::jsonb),
  ('azure_activity_log_alert_no_action_group', 'Configuration', 'Azure Activity Log Alert Has No Action Group', 'The Activity Log Alert has no action group configured, so no notifications will be sent when triggered.', 'ActivityLogAlerts', '["The Activity Log Alert has no action group configured, so no notifications will be sent when triggered."]'::jsonb, '["Configure Activity Log Alert Action Group through the Azure Portal or using Azure CLI. Refer to the documentation link below for detailed configuration steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/action-groups"]'::jsonb),
  ('azure_activity_log_alert_no_conditions', 'Configuration', 'Azure Activity Log Alert Has No Conditions', 'The Activity Log Alert has no filter conditions, meaning it will match all events.', 'ActivityLogAlerts', '["The Activity Log Alert has no filter conditions, meaning it will match all events."]'::jsonb, '["Configure Activity Log Alert Conditions through the Azure Portal or using Azure CLI. Refer to the documentation link below for detailed configuration steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/alerts-activity-log"]'::jsonb),
  ('azure_activity_log_alert_no_scopes', 'Configuration', 'Azure Activity Log Alert Has No Scopes', 'The Activity Log Alert has no scopes defined, making it inactive.', 'ActivityLogAlerts', '["The Activity Log Alert has no scopes defined, making it inactive."]'::jsonb, '["Configure Activity Log Alert Scopes through the Azure Portal or using Azure CLI. Refer to the documentation link below for detailed configuration steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/alerts-activity-log"]'::jsonb),
  ('azure_appgateway_http2_disabled', 'Configuration', 'Azure Application Gateway HTTP/2 Should Be Enabled', 'HTTP/2 is not enabled on the Application Gateway, missing performance improvements.', 'ApplicationGateway', '["HTTP/2 is not enabled on the Application Gateway, missing performance improvements."]'::jsonb, '["Enable Application Gateway HTTP/2 through the Azure Portal or using Azure CLI/Terraform. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/application-gateway/configuration-listeners"]'::jsonb)
