  ('azure_metric_alert_missing_tags', 'Configuration', 'Azure Metric Alert Should Have Tags', 'The Azure Monitor metric alert has no tags applied. Tags help organize alerts, track ownership, and enable cost allocation across your Azure environment.', 'MetricAlerts', '["The metric alert has no tags for organization."]'::jsonb, '["Configure Metric Alert Tags through the Azure Portal or using Azure CLI. Refer to the documentation link below for detailed configuration steps."]'::jsonb, '["APRA", "MAS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-resource-manager/management/tag-resources"]'::jsonb),
