  ('azure_pipeline_build_failed', 'Configuration', 'Azure Pipeline Build Has Failed', 'An Azure DevOps pipeline build has failed and requires investigation. Persistent build failures can block deployments and indicate code quality or infrastructure issues.', 'AzurePipelines', '["A pipeline build has failed and needs attention."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/devops/pipelines/troubleshooting/troubleshooting"]'::jsonb),
  ('azure_pipeline_build_no_branch', 'Configuration', 'Azure Pipeline Build Has No Branch Configuration', 'The pipeline build has no branch configuration specified.', 'AzurePipelines', '["The pipeline build has no branch configuration specified."]'::jsonb, '["Configure Pipeline Build Branch Configuration through the Azure Portal or using Azure CLI. Refer to the documentation link below for detailed configuration steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/devops/pipelines/repos/azure-repos-git"]'::jsonb),
  ('azure_pipeline_high_failure_rate', 'Configuration', 'Azure Pipeline Has High Failure Rate', 'The pipeline has a high failure rate, indicating reliability issues.', 'AzurePipelines', '["The pipeline has a high failure rate, indicating reliability issues."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/devops/pipelines/reports/pipelinereport"]'::jsonb),
  ('azure_policy_assignment_no_description', 'Configuration', 'Azure Policy Assignment Has No Description', 'The policy assignment lacks a description explaining its purpose.', 'AzurePolicy', '["The policy assignment lacks a description explaining its purpose."]'::jsonb, '["Configure Policy Assignment Description through the Azure Portal or using Azure CLI. Refer to the documentation link below for detailed configuration steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/governance/policy/overview"]'::jsonb),
  ('azure_policy_custom_definition_no_metadata', 'Configuration', 'Azure Custom Policy Definition Has No Metadata', 'The custom policy definition lacks metadata for categorization.', 'AzurePolicy', '["The custom policy definition lacks metadata for categorization."]'::jsonb, '["Configure Custom Policy Definition Metadata through the Azure Portal or using Azure CLI. Refer to the documentation link below for detailed configuration steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/governance/policy/concepts/definition-structure"]'::jsonb),
  ('azure_policy_definition_no_category', 'Configuration', 'Azure Policy Definition Has No Category', 'The policy definition is not categorized, making it harder to organize.', 'AzurePolicy', '["The policy definition is not categorized, making it harder to organize."]'::jsonb, '["Configure Policy Definition Category through the Azure Portal or using Azure CLI. Refer to the documentation link below for detailed configuration steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/governance/policy/concepts/definition-structure"]'::jsonb),
  ('azure_scheduled_query_rule_auto_mitigation_disabled', 'Configuration', 'Azure Scheduled Query Rule Auto-Mitigation Disabled', 'Auto-mitigation is disabled on this scheduled query alert rule. Without auto-mitigation, alerts will remain active even after the triggering condition resolves.', 'ScheduledQueryRules', '["Auto-mitigation is disabled on this alert rule."]'::jsonb, '["Enable Scheduled Query Rule Auto-Mitigation Disabled through the Azure Portal or using Azure CLI/Terraform. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/alerts-log"]'::jsonb),
  ('azure_scheduled_query_rule_disabled', 'Configuration', 'Azure Scheduled Query Rule Is Disabled', 'A scheduled query alert rule is disabled and will not trigger notifications. Disabled rules may leave monitoring gaps for the resources they are configured to watch.', 'ScheduledQueryRules', '["A scheduled query alert rule is disabled."]'::jsonb, '["Enable Scheduled Query Rule through the Azure Portal or using Azure CLI/Terraform. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/alerts-log"]'::jsonb),
  ('azure_scheduled_query_rule_empty_query', 'Configuration', 'Azure Scheduled Query Rule Has Empty Query', 'The scheduled query rule has no KQL query defined. Without a query, the alert rule cannot evaluate conditions and will never trigger.', 'ScheduledQueryRules', '["The query rule has no query defined."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/alerts-log"]'::jsonb),
  ('azure_scheduled_query_rule_missing_tags', 'Configuration', 'Azure Scheduled Query Rule Should Have Tags', 'The scheduled query alert rule has no tags applied. Tags help organize alerts, track ownership, and enable filtering across your Azure monitoring configuration.', 'ScheduledQueryRules', '["The query rule has no tags."]'::jsonb, '["Configure Scheduled Query Rule Tags through the Azure Portal or using Azure CLI. Refer to the documentation link below for detailed configuration steps."]'::jsonb, '["APRA", "MAS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-resource-manager/management/tag-resources"]'::jsonb),
  ('azure_scheduled_query_rule_no_action_group', 'Configuration', 'Azure Scheduled Query Rule Has No Action Group', 'No action group is configured for this scheduled query rule. Without an action group, triggered alerts will not send notifications to operators.', 'ScheduledQueryRules', '["No action group is configured for notifications."]'::jsonb, '["Configure Scheduled Query Rule Action Group through the Azure Portal or using Azure CLI. Refer to the documentation link below for detailed configuration steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/action-groups"]'::jsonb),
  ('azure_scheduled_query_rule_no_scopes', 'Configuration', 'Azure Scheduled Query Rule Has No Scopes', 'The scheduled query rule has no scopes defined, making it unable to target any resources for evaluation.', 'ScheduledQueryRules', '["The query rule has no scopes defined."]'::jsonb, '["Configure Scheduled Query Rule Scopes through the Azure Portal or using Azure CLI. Refer to the documentation link below for detailed configuration steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/alerts-log"]'::jsonb),
  ('azure_sentinel_incident_no_owner', 'Configuration', 'Azure Sentinel Incident Has No Owner', 'A Sentinel security incident has no owner assigned for investigation.', 'Sentinel', '["A Sentinel security incident has no owner assigned for investigation."]'::jsonb, '["Configure Sentinel Incident Owner through the Azure Portal or using Azure CLI. Refer to the documentation link below for detailed configuration steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/sentinel/investigate-cases"]'::jsonb),
  ('azure_sentinel_stale_incident', 'Configuration', 'Azure Sentinel Incident Is Stale', 'A Sentinel incident has been open for an extended period without progress.', 'Sentinel', '["A Sentinel incident has been open for an extended period without progress."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/sentinel/investigate-cases"]'::jsonb),
  ('azure_storage_geo_redundant_storage_disabled', 'Configuration', 'Azure Storage Geo-Redundant Replication Should Be Enabled', 'This storage account does not use geo-redundant storage (GRS). Without geo-redundancy, data is only replicated within a single region. A regional outage could result in data loss.', 'StorageAccounts', '["Upgrade storage account redundancy to GRS or RA-GRS for cross-region data protection."]'::jsonb, '["Enable geo-redundant storage:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2", "APRA"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/common/storage-redundancy"]'::jsonb),
  ('azure_storage_logging_for_delete_access_disabled', 'Configuration', 'Azure Storage Delete Access Logging Should Be Enabled', 'Storage Analytics logging for delete operations is not enabled. Without delete logging, accidental or malicious data deletion cannot be tracked.', 'StorageAccounts', '["Enable Storage Analytics logging for delete operations."]'::jsonb, '["Enable delete logging:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/common/storage-analytics-logging"]'::jsonb),
  ('azure_storage_logging_for_read_access_disabled', 'Configuration', 'Azure Storage Read Access Logging Should Be Enabled', 'Storage Analytics logging for read operations is not enabled. Without logging, read access to storage resources cannot be audited, making it difficult to detect unauthorized data access.', 'StorageAccounts', '["Enable Storage Analytics logging for read operations on blob, queue, and table services."]'::jsonb, '["Enable read logging:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/common/storage-analytics-logging"]'::jsonb),
  ('azure_storage_logging_for_write_access_disabled', 'Configuration', 'Azure Storage Write Access Logging Should Be Enabled', 'Storage Analytics logging for write operations is not enabled. Without write logging, modifications to storage data cannot be audited.', 'StorageAccounts', '["Enable Storage Analytics logging for write operations."]'::jsonb, '["Enable write logging:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/common/storage-analytics-logging"]'::jsonb),
  ('azure_storage_missing_tags', 'Configuration', 'Azure Storage Account Should Have Tags', 'This storage account has no tags applied. Tags enable cost tracking, resource organization, and governance enforcement across Azure resources.', 'StorageAccounts', '["Apply tags to the storage account for cost tracking, ownership identification, and environment classification."]'::jsonb, '["Add tags to the storage account:\n\\", "\\", "\\", ""]'::jsonb, '["APRA", "MAS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-resource-manager/management/tag-resources"]'::jsonb),
  ('azure_storage_soft_delete_disabled', 'Configuration', 'Azure Storage Soft Delete Should Be Enabled', 'Soft delete is not enabled on this storage account. Without soft delete, accidentally or maliciously deleted data cannot be recovered.', 'StorageAccounts', '["Enable blob soft delete and container soft delete with an appropriate retention period."]'::jsonb, '["Enable soft delete:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/blobs/soft-delete-blob-overview"]'::jsonb),
  ('azure_storage_versioning_disabled', 'Configuration', 'Azure Storage Blob Versioning Should Be Enabled', 'Blob versioning is not enabled. Without versioning, previous versions of blobs are lost when overwritten, making it impossible to recover from accidental overwrites or corruption.', 'StorageAccounts', '["Enable blob versioning to maintain previous versions of blobs for data protection and recovery."]'::jsonb, '["Enable blob versioning:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/blobs/versioning-overview"]'::jsonb),
  ('azure_vm_accelerated_networking_disabled', 'Configuration', 'Azure VM Accelerated Networking Should Be Enabled', 'Accelerated Networking enables single root I/O virtualization (SR-IOV) to a VM, greatly improving networking performance. This high-performance path bypasses the host from the datapath, reducing latency, jitter, and CPU utilization.', 'VirtualMachines', '["Enable Accelerated Networking on the VM''s network interface. This is supported on most general-purpose and compute-optimized VM sizes with 2 or more vCPUs."]'::jsonb, '["Enable accelerated networking (requires VM to be deallocated):\n\\", "\\", "\\", ""]'::jsonb, '["APRA", "MAS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-network/accelerated-networking-overview"]'::jsonb),
  ('azure_vm_auto_shutdown_disabled', 'Configuration', 'Azure VM Auto-Shutdown Should Be Configured', 'Auto-shutdown is not configured for this VM. For non-production workloads (dev/test environments), auto-shutdown can significantly reduce costs by automatically deallocating VMs during off-hours when they are not needed.', 'VirtualMachines', '["Configure auto-shutdown for non-production VMs to automatically deallocate them during off-hours. Set appropriate notification settings to alert users before shutdown."]'::jsonb, '["Configure auto-shutdown for the VM:\n\\", "\\", "\\", ""]'::jsonb, '["APRA", "MAS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/auto-shutdown-vm"]'::jsonb),
  ('azure_vm_automatic_os_upgrade_disabled', 'Configuration', 'Azure VM Automatic OS Upgrade Should Be Enabled', 'Automatic OS upgrades help keep VMs secure by automatically applying the latest OS patches. Without automatic upgrades, VMs may run with known vulnerabilities, increasing the attack surface.', 'VirtualMachines', '["Enable automatic OS image upgrades for the VM to ensure timely application of security patches and updates."]'::jsonb, '["Enable automatic OS upgrades via Azure Policy or during VM creation. For existing VMs, update the OS upgrade policy:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/automatic-vm-guest-patching"]'::jsonb),
  ('azure_vm_backup_disabled', 'Configuration', 'Azure VM Backup Should Be Enabled', 'Azure Virtual Machine backup is not configured. Azure Backup provides independent and isolated backups to guard against unintended data destruction. Without backup, data loss from accidental deletion, corruption, or ransomware cannot be recovered.', 'VirtualMachines', '["Enable Azure Backup for this VM using a Recovery Services vault with an appropriate backup policy. Configure retention policies that meet your organization''s RPO and RTO requirements."]'::jsonb, '["Enable backup for the VM using Azure CLI:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2", "APRA", "MAS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/backup/backup-azure-vms-first-look-arm"]'::jsonb),
  ('azure_vm_boot_diagnostics_disabled', 'Configuration', 'Azure VM Boot Diagnostics Should Be Enabled', 'Boot diagnostics is a debugging feature for Azure VMs that captures serial console output and screenshots to help diagnose VM startup issues. Without boot diagnostics, troubleshooting boot failures becomes significantly more difficult.', 'VirtualMachines', '["Enable boot diagnostics for this VM to capture serial console output and VM screenshots for troubleshooting purposes."]'::jsonb, '["Enable boot diagnostics with managed storage:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/boot-diagnostics"]'::jsonb),
  ('azure_vm_guest_level_diagnostics_missing', 'Configuration', 'Azure VM Guest-Level Diagnostics Should Be Enabled', 'Guest-level diagnostics collects OS-level metrics (memory, disk I/O, process info) from within the VM. Without guest diagnostics, you can only see host-level metrics and miss critical insights for troubleshooting and capacity planning.', 'VirtualMachines', '["Enable guest-level diagnostics by installing the Azure Diagnostics extension to collect OS-level performance counters and logs."]'::jsonb, '["Enable diagnostics using the Azure Monitor Agent:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-monitor/agents/azure-monitor-agent-overview"]'::jsonb)
INSERT INTO public.recommendation_rule_metadata
  (rule_name, category, title, description, service_name, recommendations, mitigations, compliances, "references")
VALUES
  ('azure_vm_monitor_agent_missing', 'Configuration', 'Azure VM Monitor Agent Should Be Installed', 'The Azure Monitor Agent is not installed on this VM. Without the monitoring agent, Azure Monitor cannot collect guest OS metrics, logs, and traces, limiting observability and alerting capabilities.', 'VirtualMachines', '["Install the Azure Monitor Agent to enable collection of guest OS metrics and logs for monitoring, alerting, and diagnostics."]'::jsonb, '["Install the Azure Monitor Agent:\n\\", "\\", "\\", "\n\nFor Windows VMs:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-monitor/agents/azure-monitor-agent-manage"]'::jsonb),
  ('azure_vm_unmanaged_disk', 'Configuration', 'Azure VM Should Use Managed Disks', 'This VM is using unmanaged disks (VHD files in storage accounts). Managed disks provide better reliability, scalability, and security features including built-in encryption, RBAC support, and snapshot capabilities.', 'VirtualMachines', '["Migrate from unmanaged disks to Azure Managed Disks for improved reliability, simplified management, and enhanced security features."]'::jsonb, '["Convert the VM to use managed disks:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/managed-disks-overview"]'::jsonb),
  ('azure_vmss_accelerated_networking_disabled', 'Configuration', 'Azure VMSS Accelerated Networking Should Be Enabled', 'Accelerated Networking is not enabled on this VM Scale Set. Enabling it provides lower latency, reduced jitter, and decreased CPU utilization for network-intensive workloads.', 'VirtualMachineScaleSets', '["Enable Accelerated Networking on the VMSS network interface configuration for improved network performance."]'::jsonb, '["Update the VMSS network configuration:\n\\", "\\", "\\", ""]'::jsonb, '["APRA", "MAS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-network/accelerated-networking-overview"]'::jsonb),
  ('azure_vmss_overprovision_disabled', 'Configuration', 'Azure VMSS Overprovisioning Should Be Enabled', 'Overprovisioning is disabled on this VM Scale Set. With overprovisioning enabled, Azure provisions more VMs than requested during scale-out, then deletes the extras. This reduces deployment failures and improves scale-out speed at no additional cost.', 'VirtualMachineScaleSets', '["Enable overprovisioning to improve scale-out reliability. Azure does not charge for the extra provisioned VMs."]'::jsonb, '["Enable overprovisioning:\n\\", "\\", "\\", ""]'::jsonb, '["APRA", "MAS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machine-scale-sets/virtual-machine-scale-sets-design-overview"]'::jsonb),
  ('azure_vnet_address_space_overprovisioned', 'Configuration', 'Azure VNet Address Space Is Over-Provisioned', 'The VNet has a very large address space that may not be necessary.', 'VirtualNetworks', '["The VNet has a very large address space that may not be necessary."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-network/virtual-networks-overview"]'::jsonb),
  ('azure_vnet_custom_dns_not_configured', 'Configuration', 'Azure VNet Custom DNS Is Not Configured', 'The VNet uses default Azure DNS instead of custom DNS servers.', 'VirtualNetworks', '["The VNet uses default Azure DNS instead of custom DNS servers."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-network/virtual-networks-name-resolution-for-vms-and-role-instances"]'::jsonb),
  ('azure_vnet_empty_no_subnets', 'Configuration', 'Azure VNet Has No Subnets', 'The VNet has no subnets configured, making it non-functional.', 'VirtualNetworks', '["The VNet has no subnets configured, making it non-functional."]'::jsonb, '["Configure VNet Subnets through the Azure Portal or using Azure CLI. Refer to the documentation link below for detailed configuration steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-network/virtual-network-manage-subnet"]'::jsonb),
  ('azure_vnet_gateway_transit_not_optimized', 'Configuration', 'Azure VNet Gateway Transit Is Not Optimized', 'VNet peering gateway transit is not optimally configured.', 'VirtualNetworks', '["VNet peering gateway transit is not optimally configured."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-network/virtual-network-peering-overview"]'::jsonb),
  ('aws_lambda_function_url', 'Security', 'Check Lambda Function URL Not in Use', 'A function URL is a dedicated HTTP(S) endpoint created for your Amazon Lambda function. You can use a function URL to invoke your Lambda function through a browser, curl, Postman, or an HTTP client. However, a function URL should be used with caution, and should only be applied on functions with relevant and secure access control, otherwise you risk exposing your application to the public.', 'AWSLambda', '["Check whether your Amazon Lambda functions are configured with function URLs for HTTP(S) endpoints. A function URL creates a direct HTTP(S) endpoint to your function and this may pose a security risk depending on the security configuration and intention of the function."]'::jsonb, '["**Terraform configuration file (.tf):**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/lambda/latest/dg/lambda-urls.html"]'::jsonb),
  ('aws_elasticache_encryption', 'Security', 'At Rest Encryption Should be enabled for ElastiCache Clusters', 'When working with production and confidential data it is strongly recommended to implement encryption in order to protect your data from unauthorized access and fulfill compliance requirements for data-at-rest and in-transit encryption within your organization. For example, a compliance requirement is to protect sensitive data that could potentially identify a specific individual such as Personally Identifiable Information (PII), usually used in Financial Services, Healthcare, and Telecommunications sectors.', 'AmazonElastiCache', '["Ensure that your Amazon ElastiCache Redis cache clusters are encrypted in order to meet security and compliance requirements. Encryption helps prevent unauthorized users from reading sensitive data available on your Redis cache clusters and their associated cache storage systems. This includes data saved to persistent media, known as data at-rest, and data that can be intercepted as it travels through the network, between clients and cache servers, known as data in-transit."]'::jsonb, '["**Terraform configuration file (.tf):**\n\\", "\\", "\\", "\n", "\n        AWS CLI command to enable In-Transit Encryption for ElastiCache cluster:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonElastiCache/latest/red-ug/at-rest-encryption.html"]'::jsonb),
  ('aws_elasticache_encryption_intransit', 'Security', 'At Transit Encryption Should be enabled for ElastiCache Clusters', 'When working with production and confidential data it is strongly recommended to implement encryption in order to protect your data from unauthorized access and fulfill compliance requirements for data-at-rest and in-transit encryption within your organization. For example, a compliance requirement is to protect sensitive data that could potentially identify a specific individual such as Personally Identifiable Information (PII), usually used in Financial Services, Healthcare, and Telecommunications sectors.', 'AmazonElastiCache', '["Ensure that your Amazon ElastiCache Redis cache clusters are encrypted in order to meet security and compliance requirements. Encryption helps prevent unauthorized users from reading sensitive data available on your Redis cache clusters and their associated cache storage systems. This includes data saved to persistent media, known as data at-rest, and data that can be intercepted as it travels through the network, between clients and cache servers, known as data in-transit."]'::jsonb, '["**Terraform configuration file (.tf):**\n\\", "\\", "\\", "\n", "AWS CLI command to enable In-Transit Encryption for ElastiCache cluster:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonElastiCache/latest/red-ug/in-transit-encryption.html"]'::jsonb),
  ('aws_ec2_ebs_encrypt', 'Security', 'Ec2 EBS Volumes Should be Encrypted', 'When working with production and confidential data it is strongly recommended to implement encryption in order to protect your data from unauthorized access and fulfill compliance requirements for data-at-rest and in-transit encryption within your organization. For example, a compliance requirement is to protect sensitive data that could potentially identify a specific individual such as Personally Identifiable Information (PII), usually used in Financial Services, Healthcare, and Telecommunications sectors.', 'AmazonEC2', '["Ensure that your EBS Volumes are encrypted in order to meet security and compliance requirements. Encryption helps prevent unauthorized users from reading sensitive data available on your Ec2 Instance. This includes data saved to persistent media, known as data at-rest, and data that can be intercepted as it travels through the network, between clients and cache servers, known as data in-transit."]'::jsonb, '["**By Default Enable Encryption for EBS Volumes**\n\\", "\\", "\\", "\n", "**Enable Encryption for Existing EBS Volumes**\n        1. Create a snapshot of the EBS volume\n        2. Copy snapshot (unencrypted) to an encrypted copy using AWS Managed Key\n        3. Create a new EBS volume from the encrypted snapshot in the same Availability Zone as your EC2 instance\n        4. Attach the new (encrypted) volume to the Amazon EC2 instance on a different device\n        5. Restart the encrypted EC2 instance\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/ebs/latest/userguide/ebs-encryption.html"]'::jsonb),
  ('aws_ec2_instance_public_ip', 'Security', 'Disable Public IP Address Assignment for EC2 Instances', 'Amazon EC2 instances should not get public IP addresses at launch in order to enhance security by reducing the attack surface. Instead, they should be placed in private VPC subnets and accessed through the associated load balancer. This setup ensures that incoming traffic is tightly controlled and monitored.', 'AmazonEC2', '["Ensure that Amazon EC2 instances such as backend instances are not using public IP addresses in order to prevent Internet exposure. Backend instances are EC2 instances that run behind a load balancer and do not need direct access to the Internet, therefore do not require public IP addresses."]'::jsonb, '["**Launch Command Without Public IP Address**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/using-instance-addressing.html"]'::jsonb),
  ('aws_ec2_instance_public_subnet', 'Security', 'EC2 Instances Should Not Be Launched in Public Subnets', 'By provisioning Amazon EC2 instances within a private subnet (logically isolated section of VPC) you will prevent your instances from receiving inbound traffic initiated by someone on the Internet, therefore have the guarantee that no malicious requests can reach your backend instances.', 'AmazonEC2', '["Ensure that no backend Amazon EC2 instances are provisioned in public subnets in order to protect them from exposure to the Internet. Backend instances are EC2 instances that do not require direct access to the public internet such as database, API, or caching servers. To follow cloud security best practices, all Amazon EC2 instances that are not Internet-facing should run within a private subnet, behind a NAT gateway that allows downloading software updates and implementing security patches or accessing other AWS services like SQS and SNS."]'::jsonb, '["To move your backend Amazon EC2 instances from public subnets to private subnets, you must re-create these instances within private VPC subnets.\n         - Run create-image command (OSX/Linux/UNIX) to create an image from the source, non-compliant backend EC2 instance. Include the --no-reboot command parameter to guarantee the file system integrity for your new AMI\n         - Execute run-instances command (OSX/Linux/UNIX) to launch a new backend Amazon EC2 instance from the AMI created at the previous steps. Use the information returned at step no. 2 for the instance configuration parameters. Configure the --subnet-id command parameter with the ID of your private VPC subnet and include the --no-associate-public-ip-address parameter in the command request to avoid assigning automatically a public IPv4 address to the new EC2 instance         \n\\", "\\", "\\", "\n        "]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/using-instance-addressing.html"]'::jsonb),
  ('aws_ec2_instance_generation_upgrade', 'Security', 'Ec2 Instance generation Upgrade', 'Using the current (latest) generation of EC2 instance types instead of the previous generation has multiple advantages such as better hardware performance (faster CPUs, increased memory and network throughput), better virtualization technology (HVM), and lower costs.', 'AmazonEC2', '["Ensure that all your Amazon EC2 instances are using the latest generation of instance types in order to get the best performance with lower costs."]'::jsonb, '["**Terraform configuration file (.tf):**\n\\", "\\", "\\", "\n", "AWS CLI command to upgrade EC2 instance generation:\n\n        - Run stop-instances command (OSX/Linux/UNIX) to stop the Amazon EC2 instance that you want to reconfigure:\n\\", "\\", "\\", "\n\n        - Run modify-instance-attribute command (OSX/Linux/UNIX) to change the instance type of the stopped Amazon EC2 instance to the latest generation:\n\\", "\\", "\\", "\n\n        - Run start-instances command (OSX/Linux/UNIX) to start the Amazon EC2 instance with the new instance type:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/instance-types.html"]'::jsonb),
  ('aws_ecr_pushscan_enabled', 'Security', 'Enable Scan on Push for ECR Container Images', 'For the security and compliance status of your applications it is crucial to detect and respond to Amazon ECR container image vulnerabilities in the early stages of deployment. When Scan on Push security feature is enabled, your container images are automatically scanned after being pushed to your Amazon ECR repository. If Scan on Push is disabled on your repository, then each image scan must be manually started to get scan results.', 'AmazonECR', '["Ensure that all your Amazon ECR container images are automatically scanned for security vulnerabilities and expenses after being pushed to a repository. Scan on Push for Amazon ECR is an automated vulnerability assessment feature that helps you improve the security of your ECR container images by scanning them for a broad range of Operating System (OS) vulnerabilities after being pushed to an ECR repository. The security feature uses the Common Vulnerabilities and Exposures (CVEs) database from Clair, an open source project designed for static analysis of security issues in appc and docker containers."]'::jsonb, '["**AWS CLI command to enable Scan on Push for ECR repository:**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonECR/latest/userguide/encryption-at-rest.html"]'::jsonb),
  ('aws_eks_public_access', 'Security', 'EKS Cluster Endpoint Public Access', 'When launching a cluster on Amazon EKS, an endpoint is automatically generated for the Kubernetes API server. This endpoint allows you to interact with your newly created cluster. By default, this API server endpoint is publicly accessible, meaning any machine on the internet can potentially connect to your EKS cluster using its public endpoint. This exposes your cluster to a higher risk of malicious activities and attacks. Restricting public access to the Kubernetes API endpoint managed by the EKS cluster is a security best practice that helps protect your cluster from unauthorized access and potential security threats. By not allowing public access to the cluster''s Kubernetes API endpoint, you ensure that only authorized entities can interact with your Amazon EKS cluster.', 'AmazonEKS', '["Ensure that your Amazon EKS cluster''s Kubernetes API server endpoint is not publicly accessible from the Internet in order to avoid exposing private data and minimizing security risks. The level of access to your Kubernetes API server endpoints depends on your EKS application use cases, however, for most use cases Cloud Conformity recommends that the API server endpoints should be accessible only from within your AWS Virtual Private Cloud (VPC)."]'::jsonb, '["***AWS CLI command to restrict public access to EKS cluster endpoint:***\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/eks/latest/userguide/cluster-endpoint.html"]'::jsonb),
  ('aws_eks_secret_encryption', 'Security', 'Enable Envelope Encryption for EKS Kubernetes Secrets', 'When working with security-critical data, it is strongly recommended to enable encryption of Kubernetes secrets in order to protect your data from unauthorized access and fulfill compliance requirements for data-at-rest encryption within your organization. For example, a compliance requirement is to protect sensitive data that could potentially identify a specific individual such as Personally Identifiable Information (PII), usually used for financial processing systems and healthcare services.', 'AmazonEKS', '["Use AWS Key Management Service (KMS) keys to provide envelope encryption of Kubernetes secrets stored in Amazon Elastic Kubernetes Service (EKS), in order to meet security and compliance requirements. Implementing envelope encryption of Kubernetes secrets is considered a security best practice for applications that store sensitive and confidential data. Set up your own AWS KMS Customer Master Key (CMK) and associate the key with your Amazon EKS cluster. When secrets are stored using the Kubernetes secrets API, they are encrypted with a Kubernetes-generated data encryption key, which is then further encrypted using the associated KMS CMK that you have created."]'::jsonb, '["**AWS CLI command to enable Envelope Encryption for EKS Kubernetes Secrets:**\n\\", "\\", "\\", "\n\n**Enable For Existing Cluster:**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/eks/latest/userguide/enable-kms.html"]'::jsonb),
  ('aws_lambda_environment_variable_encryption', 'Security', 'Enable Encryption in Transit for Environment Variables', 'When dealing with Lambda function environment variables that hold sensitive and critical data, it is highly recommended to implement encryption in order to protect the data that you dynamically pass to your functions (usually access information) from unauthorized access.', 'AWSLambda', '["Ensure that all Amazon Lambda function environment variables that store sensitive information such as passwords, tokens and access keys are encrypted in order to meet security and compliance requirements. The environment variables defined for your Lambda functions are key-value pairs that are used to store configuration settings without the need to change function code. By default, all Lambda environment variables with the key (name) set to \"pass\", \"password\", \"*token*\" (i.e. any key that has \"token\" string in it), \"api\", \"API\", \"Key\", \"KEY\", \"key\" are encrypted"]'::jsonb, '["**Terraform configuration file (.tf):**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/lambda/latest/dg/configuration-envvars.html"]'::jsonb),
  ('aws_rds_public_access', 'Security', 'RDS Should Not Be Publicly Accessible', 'When the security group associated with an Amazon RDS database instance allows unrestricted access (i.e. 0.0.0.0/0), everyone and everything on the Internet can establish a connection to your database instance and this can increase the opportunity for malicious activities such as brute-force attacks, SQL injection or DDoS attacks.', 'AmazonRDS', '["Check for any public-facing Amazon RDS database instances provisioned within your AWS cloud account and restrict unauthorized access in order to minimize security risks. To restrict access to a publicly accessible database instance, you must disable the PubliclyAccessible configuration flag, and update the security group associated with the database instance."]'::jsonb, '["**Terraform configuration file (.tf):**\n\\", "\\", "\\", "\n", "**AWS CLI command to disable Public Access for RDS instance:**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/CHAP_CommonTasks.Connect.html"]'::jsonb),
  ('aws_rds_storage_encrypted', 'Security', 'RDS Encryption Enabled', 'When dealing with production databases that hold sensitive and critical data, it is highly recommended to implement encryption in order to protect your data from unauthorized access. With Amazon RDS encryption enabled, the data stored on the instance underlying storage, the automated backups, Read Replicas, and snapshots, become all encrypted. The RDS encryption keys implement AES-256 algorithm and are entirely managed and protected by the AWS key management infrastructure through Amazon Key Management Service (KMS).', 'AmazonRDS', '["Ensure that your Amazon RDS database instances are encrypted to fulfill compliance requirements for data-at-rest encryption. The data encryption and decryption process is handled transparently and does not require any additional action from you or your application."]'::jsonb, '["**Terraform configuration file (.tf):**\n\\", "\\", "\\", "\n", "**AWS CLI command to enable Encryption at Rest for RDS instance:**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/Overview.Encryption.html"]'::jsonb),
  ('aws_rds_instance_public_subnet', 'Security', 'RDS Instance Should Not Be Launched in Public Subnets', 'By provisioning your Amazon RDS instances within private subnets (logically isolated sections of AWS VPC), you will prevent these resources from receiving inbound traffic from the public Internet, therefore you can have the guarantee that no malicious requests can reach your database instances from the Internet.', 'AmazonRDS', '["Ensure that no Amazon RDS database instances are provisioned inside VPC public subnets in order to protect them from direct exposure to the Internet. Because database instances are not Internet-facing and their management (running software updates, implementing security patches, etc) is performed by AWS, the database instances should run only in private subnets."]'::jsonb, '["**Terraform configuration file (.tf):**\n\\", "\\", "\\", "\n", "**AWS CLI command to move RDS instance from public to private subnet:**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_VPC.WorkingWithRDSInstanceinaVPC.html"]'::jsonb),
  ('aws_rds_snapshot_encryption', 'Security', 'RDS snapshots should be encrypted', 'When working with production databases that hold sensitive and critical data, it is strongly recommended to implement encryption at rest and protect your data from attackers or unauthorized personnel.', 'AmazonRDS', '["Ensure that your manual Amazon RDS database snapshots are encrypted in order to achieve compliance for data-at-rest encryption within your organization. The Amazon RDS snapshot encryption and decryption process is handled transparently and does not require any additional action from you or your application. The keys used for database snapshot encryption can be entirely managed and protected by the AWS key management infrastructure or fully managed by the AWS customer through Amazon KMS Customer Master Keys (CMKs)."]'::jsonb, '["**Terraform configuration file (.tf):**\n\\", "\\", "\\", "\n", "**AWS CLI command to enable Encryption for RDS snapshot:**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/Overview.Encryption.html"]'::jsonb),
  ('aws_s3_public_access_acl', 'Security', 'S3 Bucket Public ''READ_ACP'' Access', 'Granting public READ_ACP access to your Amazon S3 buckets can enable the unauthorized users to see who controls your S3 objects and how. Malicious users can use this information to find S3 objects with misconfigured permissions and try probing techniques to facilitate access to your Amazon S3 data. To meet security and compliance requirements, avoid granting READ_ACP (VIEW) permissions to the "Everyone (public access)" grantee in production.', 'AmazonS3', '["Ensure that the content permissions of your Amazon S3 buckets can''t be viewed by anonymous users in order to protect your S3 data against unauthorized access. An Amazon S3 bucket that grants public READ_ACP (VIEW) access can allow everyone on the Internet to examine your Access Control List (ACL) configuration and find permission vulnerabilities."]'::jsonb, '["**AWS CLI command to remove public READ_ACP access from S3 bucket:**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonS3/latest/userguide/access-control-block-public-access.html"]'::jsonb),
  ('aws_s3_public_access_policy', 'Security', 'S3 Bucket Public Access Via Policy', 'Granting public access to your Amazon S3 buckets via bucket policies can allow malicious users to view, get, upload, modify, and delete S3 objects, which can lead to data breaches, data loss and unexpected charges on your AWS monthly bill.', 'AmazonS3', '["Ensure that your Amazon S3 buckets are not publicly accessible to the Internet via bucket policies in order to protect against unauthorized access. Allowing unrestricted access through bucket policies gives everyone the ability to list the objects within the bucket (ListBucket), download objects (GetObject), upload/delete objects (PutObject, DeleteObject), view objects permissions (GetBucketAcl), edit objects permissions (PutBucketAcl) and more. Trend Micro Cloud One™ – Conformity strongly recommends using bucket policies to limit the access to a trusted entity, such as an authorized AWS account, instead of providing access to everyone on the Internet."]'::jsonb, '["**AWS CLI command to remove public access via bucket policy:**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonS3/latest/userguide/access-control-block-public-access.html"]'::jsonb),
  ('aws_fargate_task_definition_secrets_not_used', 'Security', 'Fargate Task Definition Not Using Secrets', 'The container has environment variables with sensitive values instead of using secrets from Secrets Manager or SSM.', 'AWSFargate', '["Use AWS Secrets Manager or SSM Parameter Store for sensitive values instead of environment variables."]'::jsonb, '["secrets"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonECS/latest/developerguide/specifying-sensitive-data.html"]'::jsonb),
  ('aws_fargate_task_definition_privileged_container', 'Security', 'Fargate Task Definition Running Privileged Container', 'The container is configured to run in privileged mode, which provides unrestricted host access.', 'AWSFargate', '["Disable privileged mode unless absolutely necessary."]'::jsonb, '["privileged"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonECS/latest/developerguide/task_definition_parameters.html"]'::jsonb),
  ('aws_fargate_task_definition_readonly_root_fs_disabled', 'Security', 'Fargate Task Definition Read-Only Root Filesystem Disabled', 'The container root filesystem is writable, increasing the attack surface.', 'AWSFargate', '["Enable read-only root filesystem and use volumes for writable paths."]'::jsonb, '["readonlyRootFilesystem"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonECS/latest/developerguide/task_definition_parameters.html"]'::jsonb),
  ('aws_redshift_encryption_at_rest', 'Security', 'Redshift Encryption at Rest Should Be Enabled', 'The Redshift cluster does not have encryption at rest enabled.', 'AmazonRedshift', '["Enable encryption at rest for the Redshift cluster to protect data."]'::jsonb, '["\n**Enable encryption via:**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/redshift/latest/mgmt/working-with-db-encryption.html"]'::jsonb),
  ('aws_redshift_public_access', 'Security', 'Redshift Cluster Should Not Be Publicly Accessible', 'The Redshift cluster is publicly accessible, exposing it to potential unauthorized access.', 'AmazonRedshift', '["Disable public accessibility for the Redshift cluster."]'::jsonb, '["\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/redshift/latest/mgmt/managing-clusters-vpc.html"]'::jsonb),
  ('aws_redshift_enhanced_vpc_routing', 'Security', 'Redshift Enhanced VPC Routing Should Be Enabled', 'Enhanced VPC routing forces all COPY and UNLOAD traffic to go through the VPC.', 'AmazonRedshift', '["Enable enhanced VPC routing to keep data traffic within the VPC."]'::jsonb, '["\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/redshift/latest/mgmt/enhanced-vpc-routing.html"]'::jsonb),
  ('aws_es_encryption_at_rest', 'Security', 'Elasticsearch Encryption at Rest Should Be Enabled', 'The Elasticsearch domain does not have encryption at rest enabled.', 'AmazonES', '["Enable encryption at rest to protect stored data."]'::jsonb, '["Update the domain configuration to enable encryption at rest."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/opensearch-service/latest/developerguide/encryption-at-rest.html"]'::jsonb),
  ('aws_es_node_to_node_encryption', 'Security', 'Elasticsearch Node-to-Node Encryption Should Be Enabled', 'Node-to-node encryption is not enabled for the Elasticsearch domain.', 'AmazonES', '["Enable node-to-node encryption to protect data in transit within the cluster."]'::jsonb, '["Update the domain configuration to enable node-to-node encryption."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/opensearch-service/latest/developerguide/ntn.html"]'::jsonb),
  ('aws_ec2_instance_imds_token_optional', 'Security', 'EC2 Instance IMDSv2 Not Required', 'The instance metadata service allows IMDSv1 which is vulnerable to SSRF attacks.', 'AmazonEC2', '["Require IMDSv2 (token-based) to protect against SSRF attacks."]'::jsonb, '["\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/configuring-instance-metadata-service.html"]'::jsonb),
  ('aws_ec2_stopped_instance_incurring_storage_cost', 'Security', 'Stopped EC2 Instance Still Incurring Storage Costs', 'The EC2 instance is stopped but its EBS volumes continue to incur charges.', 'AmazonEC2', '["Delete the instance and its volumes if no longer needed, or create snapshots and terminate."]'::jsonb, '["Terminate the instance or detach and delete unnecessary volumes."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/Stop_Start.html"]'::jsonb),
  ('aws_msk_encryption_in_transit', 'Security', 'MSK Encryption in Transit Should Be Enabled', 'Data in transit between MSK brokers is not encrypted.', 'AmazonMSK', '["Enable TLS encryption for data in transit between brokers and clients."]'::jsonb, '["Update the cluster encryption settings to enable in-transit encryption."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/msk/latest/developerguide/msk-encryption.html"]'::jsonb),
  ('aws_msk_encryption_at_rest', 'Security', 'MSK Encryption at Rest Should Be Enabled', 'Data at rest is not encrypted with a CMK for the MSK cluster.', 'AmazonMSK', '["Enable encryption at rest using a CMK for the MSK cluster."]'::jsonb, '["Encryption at rest can only be set at cluster creation time."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/msk/latest/developerguide/msk-encryption.html"]'::jsonb),
  ('aws_msk_public_access_disabled', 'Security', 'MSK Public Access Should Be Disabled', 'Public access is enabled for the MSK cluster, exposing it to the internet.', 'AmazonMSK', '["Disable public access to the MSK cluster."]'::jsonb, '["Update the cluster connectivity settings to disable public access."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/msk/latest/developerguide/public-access.html"]'::jsonb),
  ('aws_cloudtrail_encryption_cmk', 'Security', 'CloudTrail Should Use CMK Encryption', 'CloudTrail logs are not encrypted with a customer managed KMS key.', 'AWSCloudTrail', '["Encrypt CloudTrail logs with a CMK for enhanced security."]'::jsonb, '["\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/awscloudtrail/latest/userguide/encrypting-cloudtrail-log-files-with-aws-kms.html"]'::jsonb),
