  ('azure_frontdoor_enable_waf', 'Security', 'Front Door WAF Should Be Enabled', 'Web Application Firewall (WAF) is not enabled on the Azure Front Door profile. WAF provides protection against common web exploits such as SQL injection and cross-site scripting.', 'AzureFrontDoor', '["Enable WAF to protect against web application attacks."]'::jsonb, '["Create and associate a WAF policy with the Front Door endpoint."]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/web-application-firewall/afds/afds-overview"]'::jsonb),
