  ('aws_elasticache_encryption_at_rest', 'Security', 'ElastiCache Encryption at Rest Should Be Enabled', 'Amazon ElastiCache clusters should have encryption at rest enabled to protect sensitive data stored in cache. Encryption at rest uses AWS KMS keys to encrypt the data on disk, backups, and replicas, ensuring compliance with data protection regulations.', 'AmazonElastiCache', '["Enable encryption at rest for ElastiCache clusters. Note that encryption at rest can only be enabled during cluster creation \\u2014 existing clusters without encryption must be recreated with encryption enabled."]'::jsonb, '["Create a new ElastiCache cluster with encryption at rest enabled:\n\\", "\\", "\\", "\n\nMigrate data from the unencrypted cluster to the new encrypted cluster, then update your application configuration to point to the new cluster."]'::jsonb, '["CIS", "NIST4", "SOC2", "HIPAA", "PCI-DSS"]'::jsonb, '["https://docs.aws.amazon.com/AmazonElastiCache/latest/red-ug/at-rest-encryption.html"]'::jsonb),
  ('aws_elasticache_encryption_in_transit', 'Security', 'ElastiCache Encryption in Transit Should Be Enabled', 'Amazon ElastiCache clusters should have encryption in transit (TLS) enabled to protect data as it moves between clients and the cache cluster. Without encryption in transit, data including credentials and sensitive application data can be intercepted.', 'AmazonElastiCache', '["Enable encryption in transit for ElastiCache clusters to ensure all communication between clients and the cache is encrypted using TLS. Update client applications to connect using TLS-enabled endpoints."]'::jsonb, '["Create a new ElastiCache cluster with encryption in transit enabled:\n\\", "\\", "\\", "\n\nUpdate application connection strings to use the TLS endpoint and port 6380."]'::jsonb, '["CIS", "NIST4", "SOC2", "HIPAA", "PCI-DSS"]'::jsonb, '["https://docs.aws.amazon.com/AmazonElastiCache/latest/red-ug/in-transit-encryption.html"]'::jsonb),
  ('aws_guardduty_not_enabled', 'Security', 'AWS GuardDuty Should Be Enabled', 'Amazon GuardDuty is a threat detection service that continuously monitors for malicious activity and unauthorized behavior. It analyzes CloudTrail events, VPC Flow Logs, and DNS logs to identify threats such as compromised instances, reconnaissance, and account compromise.', 'AmazonGuardDuty', '["Enable Amazon GuardDuty in all AWS regions to ensure comprehensive threat detection coverage. Configure GuardDuty to send findings to a central security account for aggregated monitoring."]'::jsonb, '["Enable GuardDuty in the current region:\n\\", "\\", "\\", "\n\nTo enable in all regions:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2", "APRA", "MAS"]'::jsonb, '["https://docs.aws.amazon.com/guardduty/latest/ug/guardduty_settingup.html"]'::jsonb),
  ('azure_aks_enable_rbac', 'Security', 'Azure AKS RBAC Should Be Enabled', 'RBAC is not enabled on this AKS cluster. Without RBAC, all authenticated users have full cluster admin access.', 'AKS', '["RBAC is not enabled on this AKS cluster. Without RBAC, all authenticated users have full cluster admin access."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/aks/manage-azure-rbac"]'::jsonb),
  ('azure_app_service_client_cert_disabled', 'Security', 'Azure App Service Client Certificate Should Be Required', 'Client certificate authentication is not enabled, meaning any client can access the service without presenting a certificate.', 'AppService', '["Client certificate authentication is not enabled, meaning any client can access the service without presenting a certificate."]'::jsonb, '["Enable App Service Client Certificate Should Be Required through the Azure Portal or using Azure CLI/Terraform. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/app-service/app-service-web-configure-tls-mutual-auth"]'::jsonb),
  ('azure_bot_service_managed_identity_disabled', 'Security', 'Azure Bot Service Managed Identity Should Be Enabled', 'Managed identity is not configured for this Bot Service, requiring credentials to be stored in configuration.', 'BotService', '["Managed identity is not configured for this Bot Service, requiring credentials to be stored in configuration."]'::jsonb, '["Enable Bot Service Managed Identity through the Azure Portal or using Azure CLI/Terraform. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/bot-service/bot-builder-authentication-managed-identity"]'::jsonb),
  ('azure_bot_service_public_network_access_enabled', 'Security', 'Azure Bot Service Public Network Access Should Be Restricted', 'Public network access is enabled, exposing the Bot Service to the internet.', 'BotService', '["Public network access is enabled, exposing the Bot Service to the internet."]'::jsonb, '["Disable or restrict Bot Service Public Network Access through the Azure Portal or using Azure CLI. Refer to the documentation for detailed steps."]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/bot-service/dl-network-isolation-concept"]'::jsonb),
