  ('azure_disk_unattached_unencrypted', 'Security', 'Azure Unattached Disk Is Not Encrypted', 'An unattached disk is not encrypted, potentially exposing data at rest.', 'ManagedDisks', '["An unattached disk is not encrypted, potentially exposing data at rest."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/disk-encryption-overview"]'::jsonb),
  ('azure_dns_add_caa_record', 'Security', 'Azure DNS Zone Should Have CAA Records', 'No CAA records are configured, allowing any CA to issue certificates for the domain.', 'DNS', '["No CAA records are configured, allowing any CA to issue certificates for the domain."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/dns/dns-faq"]'::jsonb),
  ('azure_entra_id_guest_with_privileged_role', 'Security', 'Azure Entra ID Guest Users Should Not Have Privileged Roles', 'Guest users have been assigned privileged roles, which could lead to unauthorized access.', 'EntraID', '["Guest users have been assigned privileged roles, which could lead to unauthorized access."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/entra/identity/role-based-access-control/security-planning"]'::jsonb),
  ('azure_entra_id_service_principal_certificates_expired', 'Security', 'Azure Service Principal Certificate Has Expired', 'A service principal''s certificate has expired, potentially causing authentication failures.', 'EntraID', '["A service principal''s certificate has expired, potentially causing authentication failures."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/entra/identity-platform/certificate-credentials"]'::jsonb),
  ('azure_entra_id_service_principal_certificates_expiring_soon', 'Security', 'Azure Service Principal Certificate Expiring Soon', 'A service principal''s certificate will expire soon and should be renewed.', 'EntraID', '["A service principal''s certificate will expire soon and should be renewed."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/entra/identity-platform/certificate-credentials"]'::jsonb),
  ('azure_eventgrid_domain_local_auth_enabled', 'Security', 'Azure Event Grid Domain Local Auth Should Be Disabled', 'Local authentication is enabled, which is less secure than Azure AD authentication.', 'EventGrid', '["Local authentication is enabled, which is less secure than Azure AD authentication."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/event-grid/authenticate-with-access-keys-shared-access-signatures"]'::jsonb),
  ('azure_eventgrid_domain_public_access_enabled', 'Security', 'Azure Event Grid Domain Public Access Should Be Restricted', 'Public network access is enabled on the Event Grid domain.', 'EventGrid', '["Public network access is enabled on the Event Grid domain."]'::jsonb, '["Disable or restrict Event Grid Domain Public Access through the Azure Portal or using Azure CLI. Refer to the documentation for detailed steps."]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/event-grid/configure-firewall"]'::jsonb),
  ('azure_eventgrid_topic_no_managed_identity', 'Security', 'Azure Event Grid Topic Should Use Managed Identity', 'Managed identity is not configured for this Event Grid topic.', 'EventGrid', '["Managed identity is not configured for this Event Grid topic."]'::jsonb, '["Configure Event Grid Topic Should Use Managed Identity through the Azure Portal or using Azure CLI. Refer to the documentation link below for detailed configuration steps."]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/event-grid/managed-service-identity"]'::jsonb),
  ('azure_eventgrid_topic_public_access_no_ip_filter', 'Security', 'Azure Event Grid Topic Public Access Without IP Filter', 'Public access is enabled without IP filtering, allowing connections from any network.', 'EventGrid', '["Public access is enabled without IP filtering, allowing connections from any network."]'::jsonb, '["Configure Event Grid Topic Public Access Without IP Filter through the Azure Portal or using Azure CLI. Refer to the documentation link below for detailed configuration steps."]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/event-grid/configure-firewall"]'::jsonb),
  ('azure_files_enable_smb_encryption', 'Security', 'Azure Files SMB Encryption Should Be Enabled', 'SMB encryption is not enabled for Azure Files, leaving data in transit unencrypted.', 'AzureFiles', '["SMB encryption is not enabled for Azure Files, leaving data in transit unencrypted."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4", "SOC2", "HIPAA", "PCI-DSS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/files/storage-files-smb-multichannel-performance"]'::jsonb),
  ('azure_firewall_enable_threat_intel', 'Security', 'Azure Firewall Threat Intelligence Should Be Enabled', 'Threat intelligence-based filtering is not enabled, missing automatic blocking of known malicious IPs.', 'AzureFirewall', '["Threat intelligence-based filtering is not enabled, missing automatic blocking of known malicious IPs."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/firewall/threat-intel"]'::jsonb),
  ('azure_frontdoor_enable_https_redirect', 'Security', 'Azure Front Door HTTPS Redirect Should Be Enabled', 'HTTP to HTTPS redirect is not configured, allowing unencrypted connections.', 'FrontDoor', '["HTTP to HTTPS redirect is not configured, allowing unencrypted connections."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/frontdoor/front-door-how-to-redirect-https"]'::jsonb),
  ('azure_mariadb_ssl_disabled', 'Security', 'Azure MariaDB SSL Enforcement Should Be Enabled', 'SSL enforcement is disabled, allowing unencrypted database connections.', 'MariaDB', '["SSL enforcement is disabled, allowing unencrypted database connections."]'::jsonb, '["Enable MariaDB SSL Enforcement through the Azure Portal or using Azure CLI/Terraform. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4", "SOC2", "HIPAA", "PCI-DSS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/mariadb/concepts-ssl-connection-security"]'::jsonb),
  ('azure_ml_workspace_hbi_not_enabled', 'Security', 'Azure ML Workspace High Business Impact Should Be Enabled', 'High business impact mode is not enabled, which provides additional data isolation.', 'MachineLearning', '["High business impact mode is not enabled, which provides additional data isolation."]'::jsonb, '["Enable ML Workspace High Business Impact through the Azure Portal or using Azure CLI/Terraform. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/machine-learning/concept-data-encryption"]'::jsonb),
  ('azure_ml_workspace_managed_identity_disabled', 'Security', 'Azure ML Workspace Managed Identity Should Be Enabled', 'Managed identity is not configured for the ML workspace.', 'MachineLearning', '["Managed identity is not configured for the ML workspace."]'::jsonb, '["Enable ML Workspace Managed Identity through the Azure Portal or using Azure CLI/Terraform. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/machine-learning/how-to-identity-based-service-authentication"]'::jsonb),
  ('azure_ml_workspace_public_network_access_enabled', 'Security', 'Azure ML Workspace Public Network Access Should Be Disabled', 'Public network access is enabled on the ML workspace.', 'MachineLearning', '["Public network access is enabled on the ML workspace."]'::jsonb, '["Disable or restrict ML Workspace Public Network Access through the Azure Portal or using Azure CLI. Refer to the documentation for detailed steps."]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/machine-learning/how-to-configure-private-link"]'::jsonb),
  ('azure_redis_enable_non_ssl_port', 'Security', 'Azure Redis Non-SSL Port Should Be Disabled', 'The non-SSL port (6379) is enabled, allowing unencrypted connections.', 'RedisCache', '["The non-SSL port (6379) is enabled, allowing unencrypted connections."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4", "SOC2", "HIPAA", "PCI-DSS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-cache-for-redis/cache-configure"]'::jsonb),
  ('azure_redis_non_ssl_port_enabled', 'Security', 'Azure Redis Cache Non-SSL Port Is Enabled', 'Non-SSL port is enabled on this Redis Cache instance, exposing data in transit.', 'RedisCache', '["Non-SSL port is enabled on this Redis Cache instance, exposing data in transit."]'::jsonb, '["Disable or restrict Redis Cache Non-SSL Port Is Enabled through the Azure Portal or using Azure CLI. Refer to the documentation for detailed steps."]'::jsonb, '["CIS", "NIST4", "SOC2", "HIPAA", "PCI-DSS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-cache-for-redis/cache-configure"]'::jsonb),
  ('azure_redis_old_tls_version', 'Security', 'Azure Redis Cache TLS Version Should Be Updated', 'The Redis Cache uses an older TLS version with known vulnerabilities.', 'RedisCache', '["The Redis Cache uses an older TLS version with known vulnerabilities."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4", "SOC2", "HIPAA", "PCI-DSS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-cache-for-redis/cache-remove-tls-10-11"]'::jsonb),
  ('azure_redis_public_network_access', 'Security', 'Azure Redis Cache Public Network Access Should Be Restricted', 'Public network access is enabled on this Redis Cache.', 'RedisCache', '["Public network access is enabled on this Redis Cache."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-cache-for-redis/cache-private-link"]'::jsonb),
  ('azure_sentinel_no_threat_intel', 'Security', 'Azure Sentinel Threat Intelligence Not Configured', 'Threat intelligence indicators are not configured in Sentinel.', 'Sentinel', '["Threat intelligence indicators are not configured in Sentinel."]'::jsonb, '["Configure Sentinel Threat Intelligence Not Configured through the Azure Portal or using Azure CLI. Refer to the documentation link below for detailed configuration steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/sentinel/understand-threat-intelligence"]'::jsonb),
  ('azure_storage_anonymous_access_enabled', 'Security', 'Azure Storage Account Anonymous Access Should Be Disabled', 'Anonymous (public) access is enabled on this storage account, allowing unauthenticated users to read data from containers. This can lead to data exposure and is a common source of cloud data breaches.', 'StorageAccounts', '["Disable anonymous access on the storage account and all containers. Use SAS tokens or Azure AD authentication for authorized access."]'::jsonb, '["Disable anonymous access:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2", "HIPAA", "PCI-DSS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/blobs/anonymous-read-access-prevent"]'::jsonb),
  ('azure_storage_cmk_disabled', 'Security', 'Azure Storage Should Use Customer-Managed Keys', 'This storage account uses Microsoft-managed keys for encryption. Customer-managed keys (CMK) provide additional control over encryption keys, including rotation, revocation, and audit capabilities.', 'StorageAccounts', '["Configure customer-managed keys stored in Azure Key Vault for storage account encryption."]'::jsonb, '["Configure CMK encryption:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2", "HIPAA"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/common/customer-managed-keys-overview"]'::jsonb),
  ('azure_storage_minimum_tls_version_not_set_to_1_2', 'Security', 'Azure Storage Minimum TLS Version Should Be 1.2', 'This storage account allows connections using TLS versions older than 1.2. Older TLS versions (1.0, 1.1) have known vulnerabilities and should be disabled to protect data in transit.', 'StorageAccounts', '["Set the minimum TLS version to 1.2 for the storage account."]'::jsonb, '["Update minimum TLS version:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2", "PCI-DSS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/common/transport-layer-security-configure-minimum-version"]'::jsonb),
  ('azure_storage_public_network_access_enabled', 'Security', 'Azure Storage Public Network Access Should Be Disabled', 'Public network access is enabled on this storage account, allowing connections from any IP address on the internet. Restricting network access to specific VNets and IP ranges reduces the attack surface.', 'StorageAccounts', '["Disable public network access and use private endpoints or VNet service endpoints for secure connectivity."]'::jsonb, '["Disable public network access:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/common/storage-network-security"]'::jsonb),
  ('azure_storage_secure_transfer_disabled', 'Security', 'Azure Storage Secure Transfer Should Be Required', 'Secure transfer (HTTPS only) is not required for this storage account. Without this setting, data can be transmitted over unencrypted HTTP connections.', 'StorageAccounts', '["Secure transfer required"]'::jsonb, '["Enable secure transfer:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2", "PCI-DSS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/common/storage-require-secure-transfer"]'::jsonb),
  ('azure_storage_shared_key_authorization_enabled', 'Security', 'Azure Storage Shared Key Authorization Should Be Disabled', 'Shared key authorization is enabled, allowing access using storage account keys. Shared keys are long-lived credentials that, if compromised, provide unrestricted access. Azure AD authentication is the recommended alternative.', 'StorageAccounts', '["Disable shared key access and use Azure AD authentication or SAS tokens with limited scope and expiration."]'::jsonb, '["Disable shared key access:\n\\", "\\", "\\", "\n\nEnsure all applications are updated to use Azure AD authentication before disabling."]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/common/shared-key-authorization-prevent"]'::jsonb),
  ('azure_vm_boot_disk_encryption_disabled', 'Security', 'Azure VM OS Disk Encryption Should Be Enabled', 'The OS disk of this Azure VM is not encrypted with Azure Disk Encryption (ADE) or server-side encryption with customer-managed keys. Disk encryption protects data at rest and helps meet organizational security and compliance requirements.', 'VirtualMachines', '["Enable Azure Disk Encryption on the OS disk using either platform-managed keys (default SSE) or customer-managed keys (CMK) stored in Azure Key Vault for enhanced control."]'::jsonb, '["Enable Azure Disk Encryption on the VM:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2", "HIPAA", "PCI-DSS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/disk-encryption-overview"]'::jsonb),
  ('azure_vm_confidential_computing_disabled', 'Security', 'Azure VM Confidential Computing Should Be Enabled', 'Azure Confidential Computing protects data in use by using hardware-based Trusted Execution Environments (TEEs). This ensures that data remains encrypted in memory and is protected from the cloud operator, making it suitable for highly sensitive workloads.', 'VirtualMachines', '["Consider deploying confidential computing VMs (DCsv2, DCsv3, or DCdsv3 series) for workloads that process highly sensitive data requiring protection from cloud operators."]'::jsonb, '["Deploy a confidential computing VM:\n\\", "\\", "\\", ""]'::jsonb, '["NIST4", "HIPAA", "PCI-DSS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/confidential-computing/overview"]'::jsonb),
  ('azure_vm_data_disk_encryption_disabled', 'Security', 'Azure VM Data Disk Encryption Should Be Enabled', 'One or more data disks attached to this Azure VM are not encrypted. Data disk encryption protects sensitive data at rest and is required for many compliance frameworks.', 'VirtualMachines', '["Enable encryption on all data disks attached to the VM using Azure Disk Encryption or server-side encryption with customer-managed keys."]'::jsonb, '["Enable encryption on all disks (OS and data):\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2", "HIPAA", "PCI-DSS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/disk-encryption-overview"]'::jsonb),
  ('azure_vm_disk_encryption_cmk_missing', 'Security', 'Azure VM Disk Should Use Customer-Managed Keys', 'Azure VM disks are encrypted with platform-managed keys by default, but customer-managed keys (CMK) provide additional control over the encryption keys, including the ability to rotate, disable, and audit key usage through Azure Key Vault.', 'VirtualMachines', '["Configure disk encryption with customer-managed keys stored in Azure Key Vault for enhanced encryption key management and compliance."]'::jsonb, '["Create a disk encryption set with a CMK and apply it:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2", "HIPAA"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/disk-encryption"]'::jsonb),
  ('azure_vm_endpoint_protection_missing', 'Security', 'Azure VM Endpoint Protection Should Be Installed', 'Endpoint protection (antimalware) is not installed on this VM. Without endpoint protection, the VM is vulnerable to malware, viruses, and other malicious software that could compromise data and workloads.', 'VirtualMachines', '["Install and configure Microsoft Antimalware or a supported third-party endpoint protection solution on the VM."]'::jsonb, '["Install Microsoft Antimalware extension:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/extensions/iaas-antimalware-windows"]'::jsonb),
  ('azure_vm_entra_id_authentication_disabled', 'Security', 'Azure VM Should Use Entra ID Authentication', 'Microsoft Entra ID (formerly Azure AD) authentication for VMs provides centralized identity management, conditional access policies, and MFA support. Using local accounts increases the risk of credential theft and makes access auditing difficult.', 'VirtualMachines', '["Enable Microsoft Entra ID login for the VM to leverage centralized identity management, conditional access policies, and audit logging."]'::jsonb, '["Install the AAD login extension:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/entra/identity/devices/howto-vm-sign-in-azure-ad-linux"]'::jsonb),
  ('azure_vm_jit_access_disabled', 'Security', 'Azure VM Just-In-Time Access Should Be Enabled', 'Just-in-time (JIT) VM access reduces exposure to attacks by locking down inbound traffic to Azure VMs and providing time-limited access when needed. Without JIT, management ports (RDP/SSH) may be permanently open, increasing the attack surface.', 'VirtualMachines', '["Enable JIT VM access through Microsoft Defender for Cloud to restrict management port access and require time-limited, approved access requests."]'::jsonb, '["Enable JIT access via Azure Portal: Navigate to Microsoft Defender for Cloud > Workload protections > Just-in-time VM access > Enable JIT on the VM.\n\nOr via CLI:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/defender-for-cloud/just-in-time-access-usage"]'::jsonb),
  ('azure_vm_ssh_password_authentication_enabled', 'Security', 'Azure VM SSH Password Authentication Should Be Disabled', 'SSH password authentication is enabled on this Linux VM. Password-based SSH authentication is vulnerable to brute-force attacks. SSH key-based authentication provides stronger security and should be used instead.', 'VirtualMachines', '["Disable SSH password authentication and use SSH key-based authentication instead. Ensure SSH keys are properly configured before disabling password authentication."]'::jsonb, '["Disable password authentication in the VM''s SSH configuration:\n\\", "\\", "\\", "\n\nThen SSH into the VM and disable password auth:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/linux/mac-create-ssh-keys"]'::jsonb),
  ('azure_vm_system_assigned_identity_disabled', 'Security', 'Azure VM System-Assigned Managed Identity Should Be Enabled', 'System-assigned managed identity provides an automatically managed identity in Microsoft Entra ID for the VM. It eliminates the need to store credentials in code and enables secure access to Azure resources through Azure RBAC.', 'VirtualMachines', '["Enable system-assigned managed identity for the VM to allow secure, credential-free access to Azure services like Key Vault, Storage, and SQL Database."]'::jsonb, '["Enable system-assigned managed identity:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/entra/identity/managed-identities-azure-resources/qs-configure-cli-windows-vm"]'::jsonb),
  ('azure_vm_trusted_launch_disabled', 'Security', 'Azure VM Trusted Launch Should Be Enabled', 'Trusted Launch protects Azure VMs against advanced and persistent attack techniques by providing Secure Boot, vTPM, and boot integrity monitoring. Without Trusted Launch, VMs are more susceptible to rootkits and boot-level malware.', 'VirtualMachines', '["Enable Trusted Launch for new VM deployments to protect against boot-level attacks with Secure Boot and vTPM capabilities."]'::jsonb, '["Create a new VM with Trusted Launch enabled:\n\\", "\\", "\\", "\n\nNote: Existing VMs cannot be upgraded to Trusted Launch. A new VM must be created."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/trusted-launch"]'::jsonb),
  ('azure_vmss_instance_public_ip_assigned', 'Security', 'Azure VMSS Instances Should Not Have Public IPs', 'VMSS instances have public IP addresses assigned directly, exposing them to the internet. This increases the attack surface and makes instances vulnerable to unauthorized access attempts.', 'VirtualMachineScaleSets', '["Remove public IP configurations from VMSS instances. Use Azure Load Balancer, Application Gateway, or Azure Bastion for controlled access."]'::jsonb, '["Remove public IP from VMSS configuration:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machine-scale-sets/virtual-machine-scale-sets-networking"]'::jsonb),
  ('azure_vmss_system_assigned_identity_disabled', 'Security', 'Azure VMSS System-Assigned Identity Should Be Enabled', 'System-assigned managed identity is not enabled on this VMSS. Managed identities eliminate the need to store credentials in code and enable secure access to Azure resources.', 'VirtualMachineScaleSets', '["Enable system-assigned managed identity for the VMSS to allow credential-free access to Azure services."]'::jsonb, '["Enable system-assigned identity:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4", "SOC2"]'::jsonb, '["https://learn.microsoft.com/en-us/entra/identity/managed-identities-azure-resources/qs-configure-cli-windows-vmss"]'::jsonb),
  ('azure_vmss_trusted_launch_disabled', 'Security', 'Azure VMSS Trusted Launch Should Be Enabled', 'Trusted Launch is not enabled on this VMSS. Trusted Launch protects against boot-level attacks with Secure Boot and vTPM capabilities.', 'VirtualMachineScaleSets', '["Enable Trusted Launch for new VMSS deployments to protect against boot-level threats."]'::jsonb, '["Create a new VMSS with Trusted Launch:\n\\", "\\", "\\", ""]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/trusted-launch"]'::jsonb),
  ('azure_vnet_service_endpoints_not_configured', 'Security', 'Azure VNet Service Endpoints Should Be Configured', 'Service endpoints are not configured, meaning traffic to Azure services goes over the public internet.', 'VirtualNetworks', '["Service endpoints are not configured, meaning traffic to Azure services goes over the public internet."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-network/virtual-network-service-endpoints-overview"]'::jsonb),
  ('azure_vnet_vm_protection_disabled', 'Security', 'Azure VNet VM Protection Is Disabled', 'VM protection is not enabled on this Azure Virtual Network. VM protection prevents accidental deletion of VMs within the VNet by requiring explicit override.', 'VirtualNetworks', '["VM protection is not enabled on the VNet."]'::jsonb, '["Enable VNet VM Protection through the Azure Portal or using Azure CLI/Terraform. Refer to the documentation link below for detailed steps."]'::jsonb, '["CIS", "NIST4"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-network/virtual-networks-overview"]'::jsonb),
  ('aws_elasticache_engine_version', 'InfraUpgrade', 'Use latest ElastiCache Engine Version', 'When your Amazon ElastiCache clusters are configured with the latest version of Redis/Memcached cache engine, you can benefit from new features and enhancements, better performance, better memory management, bug fixes and security patches. For example, upgrading your Redis cache clusters version to 3.2.6 will get you all the improvements that come with the Redis engine version 3 (data partitioning, geospatial indexing, online cluster resizing, replica scaling, etc) plus the ones added by AWS such as support for newer cache node types, in-transit and at-rest encryption, and support for HIPAA compliance. For Memcached cache clusters, upgrading the engine version to 1.4.34 will add several bug fixes, systemd service hardening, improved support for large items over 1MB and the ability to dynamically increase the amount of memory available to the engine without having to restart the cache cluster.', 'AmazonElastiCache', '["Ensure that your Amazon ElastiCache clusters are using the stable latest version of Redis/Memcached cache engine in order to adhere to AWS cloud best practices, benefit from better security by having the most recent vulnerability patches, receive the latest Redis and Memcached software features, and get the latest performance optimizations."]'::jsonb, '["**Terraform configuration file (.tf):**\n\\", "\\", "\\", "\n", "**AWS CLI command to upgrade ElastiCache engine version:**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/advisor/advisor-security-recommendations"]'::jsonb),
  ('aws_elasticache_instance_generation', 'InfraUpgrade', 'Elasticache Instance Generation should be latest', 'Using the latest generation of Amazon ElastiCache cluster nodes instead of the previous generation nodes has tangible benefits such as better hardware performance (more computing capacity and faster CPUs, memory optimization, superior I/O, and higher network throughput), better support for the newest Redis/Memcached engine versions, and lower costs for CPU, memory, and storage.', 'AmazonElastiCache', '["Ensure that all the Amazon ElastiCache cache clusters provisioned in your AWS account are using the latest generation of cache node types in order to get the best performance with lower costs. If you are using cache nodes from the previous generation, Trend Micro Cloud One™ – Conformity strongly recommends that you upgrade your nodes with their latest generation equivalents."]'::jsonb, '["**AWS CLI command to upgrade ElastiCache instance generation:**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonElastiCache/latest/dg/CacheNodes.SupportedTypes.html"]'::jsonb),
  ('aws_ec2_orphaned_volume', 'InfraUpgrade', 'EBS Volumes Should Not Be Orphaned', 'Any Amazon EBS volume provisioned in your AWS cloud account adds charges to your monthly bill, regardless of whether it is in use. If you have Amazon EBS volumes that are not attached to EC2 instances and their data is no longer needed, consider deleting these volumes. Removing unattached/orphaned Amazon EBS volumes from your AWS account will help you to avoid unexpected charges on your AWS bill and halt access to any sensitive data available on these volumes.', 'AmazonEC2', '["Identify unused (unattached) Amazon Elastic Block Store (EBS) volumes available within your AWS cloud account and delete these volumes in order to lower the cost of your AWS bill and reduce the risk of confidential and sensitive data leaks."]'::jsonb, '["**AWS CLI command to delete orphaned EBS volume:**\n        - Create Snapshot\n\\", "\\", "\\", "\n\n        - Delete Volume\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/ebs-deleting-volume.html"]'::jsonb),
  ('aws_ec2_ebs_generation_upgrade', 'InfraUpgrade', 'Use latest EBS Volume Generation', 'For same amount of storage space, gp3 is 20 percent more cost-effective than gp2 volumes. It’s also interesting to consider what a maximum performance and maximum throughput volume would cost for both gp2 and gp3', 'AmazonEC2', '["Migrate EBS volumes from GP2 to GP3 to save up to 20% on costs."]'::jsonb, '["**AWS CLI command to upgrade EBS volume generation:**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://aws.amazon.com/blogs/storage/migrate-your-amazon-ebs-volumes-from-gp2-to-gp3-and-save-up-to-20-on-costs/"]'::jsonb),
  ('aws_rds_instance_generation', 'InfraUpgrade', 'RDS Instance Generation Upgrade', 'Using the latest generation of Amazon RDS database instances instead of the previous generation instances has tangible benefits such as better hardware performance (more computing capacity and faster CPUs, memory optimization and higher network throughput), better support for latest database engines versions, and lower costs for memory and storage', 'AmazonRDS', '["Ensure that all the Amazon RDS databases instances provisioned within your AWS account are using the latest generation of instance classes in order to get the best performance with lower costs. If you are using database instances from the previous generation, Trend Micro Cloud One™ – Conformity strongly recommends that you upgrade your instances with their latest generation equivalents."]'::jsonb, '["**AWS CLI command to upgrade RDS instance generation:**\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/Concepts.DBInstanceClass.html"]'::jsonb),
  ('aws_fargate_latest_platform_version', 'InfraUpgrade', 'Fargate Task Uses Latest Platform Version', 'AWS Fargate platform versions control the runtime environment for tasks. Older platform versions may lack security patches, performance improvements, and new features. Running on the latest platform version ensures you benefit from the most recent improvements.', 'AWSFargate', '["Ensure all Fargate tasks use the LATEST platform version to benefit from security patches and performance improvements."]'::jsonb, '["Update the Fargate service or task definition to use platform version LATEST:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonECS/latest/developerguide/platform_versions.html"]'::jsonb)
INSERT INTO public.recommendation_rule_metadata
  (rule_name, category, title, description, service_name, recommendations, mitigations, compliances, "references")
VALUES
  ('aws_ecs_fargate_latest_platform_version', 'InfraUpgrade', 'ECS Fargate Service Uses Latest Platform Version', 'ECS Fargate services should run on the latest platform version to receive security fixes, kernel updates, and new features. Using outdated platform versions may expose your workloads to known vulnerabilities.', 'AmazonECS', '["Update ECS Fargate services to use the LATEST platform version."]'::jsonb, '["Update the service platform version:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/AmazonECS/latest/developerguide/platform_versions.html"]'::jsonb),
  ('aws_elasticbeanstalk_outdated_platform', 'InfraUpgrade', 'Elastic Beanstalk Uses Outdated Platform', 'AWS Elastic Beanstalk environments running on outdated or retired platform versions may miss critical security patches, bug fixes, and performance improvements. AWS regularly retires older platform branches.', 'AWSElasticBeanstalk', '["Upgrade Elastic Beanstalk environments to the latest supported platform version."]'::jsonb, '["Update the environment platform version:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/elasticbeanstalk/latest/dg/using-features.platform.upgrade.html"]'::jsonb),
  ('aws_elasticbeanstalk_unhealthy', 'InfraUpgrade', 'Elastic Beanstalk Environment Health Degraded', 'An Elastic Beanstalk environment with degraded or severe health status indicates issues with the underlying instances, deployment, or application. This can affect availability and performance.', 'AWSElasticBeanstalk', '["Investigate and resolve health issues in degraded Elastic Beanstalk environments."]'::jsonb, '["Check environment health:\n\\", "\\", "\\", "\nReview recent events and instance health to identify root cause."]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/elasticbeanstalk/latest/dg/health-enhanced.html"]'::jsonb),
  ('aws_redshift_cluster_version', 'InfraUpgrade', 'Redshift Cluster Version Upgrade', 'Amazon Redshift regularly releases new cluster versions with performance improvements, security patches, and new features. Running an outdated version may expose you to known vulnerabilities and miss optimizations.', 'AmazonRedshift', '["Ensure Redshift clusters are running the latest available version and that automatic version upgrades are enabled."]'::jsonb, '["Enable automatic version upgrades:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://docs.aws.amazon.com/redshift/latest/mgmt/cluster-versions.html"]'::jsonb),
  ('gcp_gke_old_cluster', 'InfraUpgrade', 'GKE Cluster Running Outdated Kubernetes Version', 'GKE clusters running older Kubernetes versions miss security patches, bug fixes, and new features. Google regularly deprecates older minor versions and eventually removes support.', 'GKE', '["Upgrade GKE clusters to a supported and recent Kubernetes version."]'::jsonb, '["Upgrade the cluster control plane and node pools:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://cloud.google.com/kubernetes-engine/docs/concepts/release-channels"]'::jsonb),
  ('gcp_compute_old_instance', 'InfraUpgrade', 'GCE Instance Using Outdated Machine Type', 'Google Compute Engine regularly introduces new machine type families (e.g., N2, E2, C3) with better price-performance ratios. Running instances on older machine types (N1) may cost more for less performance.', 'ComputeEngine', '["Migrate Compute Engine instances to the latest machine type generation for better performance and lower cost."]'::jsonb, '["Stop the instance, change machine type, and restart:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://cloud.google.com/compute/docs/instances/create-start-instance"]'::jsonb),
  ('gcp_sql_old_instance', 'InfraUpgrade', 'Cloud SQL Instance Running Outdated Database Version', 'Cloud SQL instances running older database engine versions (e.g., MySQL 5.7, PostgreSQL 12) may not receive security updates and lack newer features. Google eventually ends support for older versions.', 'CloudSQL', '["Upgrade Cloud SQL instances to a supported and recent database engine version."]'::jsonb, '["Upgrade the database version (requires downtime):\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://cloud.google.com/sql/docs/mysql/db-versions"]'::jsonb),
  ('gcp_storage_old_bucket', 'InfraUpgrade', 'GCS Bucket Using Legacy Storage Class', 'Google Cloud Storage buckets using legacy storage classes (e.g., Multi-Regional, Regional) should be migrated to the newer Standard, Nearline, Coldline, or Archive classes for better pricing and features.', 'CloudStorage', '["Update GCS bucket storage class from legacy to a current storage class."]'::jsonb, '["Update bucket storage class:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://cloud.google.com/storage/docs/storage-classes"]'::jsonb),
  ('azure_aks_old_kubernetes_version', 'InfraUpgrade', 'AKS Cluster Running Outdated Kubernetes Version', 'Azure Kubernetes Service clusters running outdated Kubernetes versions miss security patches and new features. Azure supports only a limited number of minor versions at any given time.', 'AKS', '["Upgrade AKS clusters to a supported and recent Kubernetes version."]'::jsonb, '["Upgrade the AKS cluster:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/aks/supported-kubernetes-versions"]'::jsonb),
  ('azure_function_old_runtime', 'InfraUpgrade', 'Azure Function Using Outdated Runtime Version', 'Azure Functions running on deprecated or outdated runtime versions may lack security patches and new features. Microsoft regularly retires older runtime versions.', 'AzureFunctions', '["Upgrade Azure Functions to the latest supported runtime version."]'::jsonb, '["Update the function app runtime version:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-functions/functions-versions"]'::jsonb),
  ('azure_managed_disk_sku_upgrade', 'InfraUpgrade', 'Azure Managed Disk SKU Upgrade Available', 'Azure Managed Disks have newer SKU options (e.g., Premium SSD v2) that offer better performance-per-cost. Standard HDD disks used for production workloads may benefit from an upgrade.', 'AzureManagedDisks', '["Consider upgrading managed disk SKU to a newer generation for better performance."]'::jsonb, '["Update disk SKU:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/disks-types"]'::jsonb),
  ('azure_disk_premium_ssd_v2_upgrade', 'InfraUpgrade', 'Azure Disk Eligible for Premium SSD v2 Upgrade', 'Premium SSD v2 offers sub-millisecond latency with independently configurable IOPS and throughput. Disks currently using Premium SSD (v1) may benefit from upgrading to v2 for better cost-performance.', 'AzureManagedDisks', '["Evaluate whether Premium SSD v2 is a better fit for workloads currently using Premium SSD v1."]'::jsonb, '["Premium SSD v2 migration requires creating a new disk and copying data. Refer to Azure documentation for migration steps."]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/disks-types"]'::jsonb),
  ('azure_expressroute_enable_standard_sku', 'InfraUpgrade', 'ExpressRoute Circuit Should Use Standard or Premium SKU', 'Azure ExpressRoute circuits using the Basic or Local SKU may have limited features. Standard or Premium SKUs provide better routing options, more virtual network links, and global reach.', 'AzureExpressRoute', '["Evaluate whether upgrading the ExpressRoute circuit SKU would benefit your connectivity requirements."]'::jsonb, '["Update ExpressRoute SKU:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/expressroute/expressroute-about-virtual-network-gateways"]'::jsonb),
  ('azure_vm_generation_upgrade', 'InfraUpgrade', 'Azure VM Using Older Generation', 'Azure regularly introduces new VM series with better price-performance. VMs running on older series (e.g., Dv2) can be upgraded to newer series (e.g., Dv5) for improved performance at similar or lower cost.', 'AzureVMs', '["Upgrade Azure VMs to the latest generation VM series for better performance and cost efficiency."]'::jsonb, '["Resize the VM:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/generation-2"]'::jsonb),
  ('azure_logic_app_outdated_workflow', 'InfraUpgrade', 'Azure Logic App Workflow Is Outdated', 'The Logic App workflow version is outdated and should be updated.', 'LogicApps', '["The Logic App workflow version is outdated and should be updated."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["APRA", "MAS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/logic-apps/logic-apps-overview"]'::jsonb),
  ('gcp_compute_generation_upgrade', 'InfraUpgrade', 'GCP Compute Instance Should Be Upgraded to Newer Generation', 'This GCP Compute Engine instance is running on an older machine type generation. Newer generation machine types offer better price-performance ratios with improved processors and hardware capabilities.', 'ComputeEngine', '["Upgrade the instance to a newer machine type generation (e.g., from N1 to N2/N2D, or E2) for improved performance and cost efficiency."]'::jsonb, '["Stop the instance and change the machine type:\n\\", "\\", "\\", ""]'::jsonb, '["APRA", "MAS"]'::jsonb, '["https://cloud.google.com/compute/docs/machine-resource"]'::jsonb),
  ('aws_rds_underutilized', 'RightSizing', 'Underutilized RDS Instance', 'Identify any Amazon RDS database instances that appear to be underutilized and downsize (resize) them to help lower the cost of your monthly AWS bill. By default, an RDS database instance is considered "underutilized" when meets the following criteria:
INSERT INTO public.recommendation_rule_metadata
  (rule_name, category, title, description, service_name, recommendations, mitigations, compliances, "references")
VALUES
  ('gcp_native_compute_image_idle_resource', 'RightSizing', 'GCP Recommender: Idle Compute Image', 'Google Cloud Recommender has identified this custom image as idle (not used to create instances). Idle images incur storage costs.', 'ComputeEngine', '["Delete unused custom images to reduce storage costs."]'::jsonb, '["Delete the image:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://cloud.google.com/recommender/docs/recommenders"]'::jsonb),
  ('gcp_native_cloudsql_instance_idle', 'RightSizing', 'GCP Recommender: Idle Cloud SQL Instance', 'Google Cloud Recommender has identified this Cloud SQL instance as idle based on very low connection and query activity. Idle instances incur full costs.', 'CloudSQL', '["Stop or delete idle Cloud SQL instances as recommended by GCP Recommender."]'::jsonb, '["Stop the instance:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://cloud.google.com/recommender/docs/recommenders"]'::jsonb),
  ('gcp_native_cloudsql_instance_overprovisioned', 'RightSizing', 'GCP Recommender: Overprovisioned Cloud SQL Instance', 'Google Cloud Recommender has identified this Cloud SQL instance as overprovisioned. The allocated CPU and memory exceed the actual workload requirements, resulting in unnecessary costs.', 'CloudSQL', '["Resize the Cloud SQL instance to a smaller machine type as recommended by GCP Recommender."]'::jsonb, '["Resize the instance (requires restart):\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://cloud.google.com/recommender/docs/recommenders"]'::jsonb),
  ('gcp_native_container_diagnosis', 'RightSizing', 'GCP Recommender: GKE Container Diagnosis', 'Google Cloud Recommender has identified potential issues with GKE container resource configurations, such as over-provisioned or under-provisioned CPU/memory requests and limits.', 'GKE', '["Review and adjust container resource requests and limits based on GCP Recommender suggestions."]'::jsonb, '["Update Kubernetes deployment manifests to adjust resource requests and limits according to the recommendation. Apply changes with kubectl apply."]'::jsonb, '[]'::jsonb, '["https://cloud.google.com/recommender/docs/recommenders"]'::jsonb),
  ('gcp_native_cloudsql_instance_underprovisioned', 'RightSizing', 'GCP Recommender: Underprovisioned Cloud SQL Instance', 'Google Cloud Recommender has identified this Cloud SQL instance as underprovisioned. The instance may experience performance issues due to insufficient CPU or memory.', 'CloudSQL', '["Upgrade the Cloud SQL instance to a larger machine type as recommended by GCP Recommender."]'::jsonb, '["Resize the instance (requires restart):\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://cloud.google.com/recommender/docs/recommenders"]'::jsonb),
  ('azure_unassociated_public_ip', 'RightSizing', 'Unassociated Azure Public IP Address', 'Azure Public IP addresses that are not associated with any resource still incur hourly charges. Unassociated IPs should be deleted if no longer needed.', 'AzureNetworking', '["Delete unassociated public IP addresses to reduce costs."]'::jsonb, '["Delete the public IP:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-network/ip-services/public-ip-addresses"]'::jsonb),
  ('azure_unused_load_balancer', 'RightSizing', 'Unused Azure Load Balancer', 'This Azure Load Balancer has no backend pool members or receives negligible traffic. Unused load balancers still incur charges.', 'AzureLoadBalancer', '["Delete unused Azure Load Balancers that have no backend pool members."]'::jsonb, '["Delete the load balancer:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/load-balancer/load-balancer-overview"]'::jsonb),
  ('azure_nic_orphaned', 'RightSizing', 'Orphaned Azure Network Interface', 'This network interface is not attached to any virtual machine. Orphaned NICs may have associated public IPs or NSGs that incur costs.', 'AzureNetworking', '["Delete orphaned network interfaces and their associated resources."]'::jsonb, '["Delete the NIC:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-network/virtual-network-network-interface"]'::jsonb),
  ('azure_disk_unattached_volume', 'RightSizing', 'Unattached Azure Managed Disk', 'This managed disk is not attached to any virtual machine. Unattached disks incur storage costs without providing value.', 'AzureManagedDisks', '["Snapshot and delete unattached managed disks to reduce storage costs."]'::jsonb, '["Create snapshot and delete disk:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/disks-find-unattached-portal"]'::jsonb),
  ('azure_storage_account_potentially_idle', 'RightSizing', 'Potentially Idle Azure Storage Account', 'This storage account has very low transaction activity over the monitoring period. It may be unused and incurring unnecessary costs.', 'AzureStorage', '["Evaluate whether this storage account is still needed. Delete or consolidate if unused."]'::jsonb, '["Review storage account usage in Azure Monitor metrics. If confirmed idle, migrate any remaining data and delete the account."]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/common/storage-account-overview"]'::jsonb),
  ('azure_appgateway_stopped', 'RightSizing', 'Stopped Azure Application Gateway', 'This Application Gateway is in a stopped state. While stopped gateways have reduced costs, they may still incur charges for the public IP and other associated resources.', 'AzureAppGateway', '["Delete stopped Application Gateways that are no longer needed."]'::jsonb, '["Delete the Application Gateway:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/application-gateway/overview"]'::jsonb),
  ('azure_app_service_stopped_app', 'RightSizing', 'Stopped Azure App Service', 'This App Service is in a stopped state but still occupies resources in its App Service Plan. If the plan is not shared with other apps, it continues to incur full charges.', 'AzureAppService', '["Delete stopped App Services that are no longer needed, or consolidate them into shared plans."]'::jsonb, '["Delete the app:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/app-service/overview"]'::jsonb),
  ('azure_redis_overprovisioned_sku', 'RightSizing', 'Azure Redis Cache Overprovisioned SKU', 'This Azure Cache for Redis instance is using a higher SKU tier or cache size than its workload requires. Downgrading can reduce costs.', 'AzureRedis', '["Evaluate Redis cache utilization and consider downgrading to a smaller SKU."]'::jsonb, '["Note: Downgrading Redis SKU requires creating a new instance with the desired SKU and migrating data. Azure does not support in-place SKU downgrades."]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-cache-for-redis/cache-overview"]'::jsonb),
  ('azure_sql_database_pricing_model_upgrade', 'RightSizing', 'Azure SQL Database Pricing Model Optimization', 'This Azure SQL Database may benefit from switching to a different pricing model (e.g., from DTU to vCore, or vice versa) based on its workload characteristics.', 'AzureSQL', '["Evaluate whether switching the Azure SQL pricing model would reduce costs for the current workload."]'::jsonb, '["Review Azure SQL Database pricing models and use the Azure pricing calculator to compare DTU vs vCore costs for your workload."]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-sql/database/service-tiers-general-purpose-business-critical"]'::jsonb),
  ('azure_sql_serverless_optimization', 'RightSizing', 'Azure SQL Serverless Optimization', 'This Azure SQL Database has intermittent usage patterns that could benefit from the serverless compute tier, which auto-pauses during inactivity and scales automatically.', 'AzureSQL', '["Consider switching to Azure SQL Serverless for databases with intermittent, unpredictable usage patterns."]'::jsonb, '["Convert to serverless:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/azure-sql/database/serverless-tier-overview"]'::jsonb),
  ('azure_storage_redundancy_optimization', 'RightSizing', 'Azure Storage Redundancy Optimization', 'This storage account may be using a higher redundancy level (e.g., GRS, RA-GRS) than required. Switching to a lower redundancy level (e.g., LRS) can reduce costs.', 'AzureStorage', '["Evaluate whether a lower storage redundancy level is acceptable for this workload."]'::jsonb, '["Change storage redundancy:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/common/storage-redundancy"]'::jsonb),
  ('azure_storage_performance_tier_upgrade', 'RightSizing', 'Azure Storage Performance Tier Optimization', 'This storage account is using a performance tier that may not match its access patterns. Standard tier may be sufficient for infrequently accessed data.', 'AzureStorage', '["Evaluate whether the storage account performance tier matches the actual access patterns."]'::jsonb, '["Review storage account metrics and consider switching between Premium and Standard tiers based on IOPS and latency requirements."]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/common/storage-account-overview"]'::jsonb),
  ('azure_storage_access_tier_optimization', 'RightSizing', 'Azure Storage Access Tier Optimization', 'This storage account contains blobs in the Hot access tier that are infrequently accessed. Moving them to Cool or Archive tier can significantly reduce storage costs.', 'AzureStorage', '["Configure lifecycle management policies to automatically move infrequently accessed blobs to cooler tiers."]'::jsonb, '["Set lifecycle management policy:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/blobs/access-tiers-overview"]'::jsonb),
  ('azure_files_unused_file_share', 'RightSizing', 'Unused Azure File Share', 'This Azure File Share has very low transaction activity and may be unused. Idle file shares still incur storage costs.', 'AzureStorage', '["Delete unused Azure File Shares to reduce storage costs."]'::jsonb, '["Delete the file share:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/files/storage-files-introduction"]'::jsonb),
  ('azure_vmss_empty', 'RightSizing', 'Empty Azure VM Scale Set', 'This VM Scale Set has zero instances but the scale set resource itself still exists. While there are no VM costs, the associated resources (load balancer, public IP) may still incur charges.', 'AzureVMSS', '["Delete empty VM Scale Sets that are no longer needed."]'::jsonb, '["Delete the scale set:\n\\", "\\", "\\", "\n"]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machine-scale-sets/overview"]'::jsonb),
  ('azure_native_advisor_cost', 'RightSizing', 'Azure Advisor: Cost Recommendation', 'Azure Advisor has identified an opportunity to reduce costs. This may include right-sizing VMs, purchasing reservations, deleting unused resources, or other cost optimizations.', 'AzureAdvisor', '["Review and implement the Azure Advisor cost recommendation to reduce your Azure spending."]'::jsonb, '["Follow the specific remediation steps provided in the Azure Advisor recommendation details. Actions vary by recommendation type."]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/advisor/advisor-cost-recommendations"]'::jsonb),
  ('azure_native_advisor_highavailability', 'RightSizing', 'Azure Advisor: High Availability Recommendation', 'Azure Advisor has identified a potential improvement for the availability of your Azure resources. This may include enabling zone redundancy, configuring backup, or other HA improvements.', 'AzureAdvisor', '["Review and implement the Azure Advisor high availability recommendation to improve resilience."]'::jsonb, '["Follow the specific remediation steps provided in the Azure Advisor recommendation details."]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/advisor/advisor-high-availability-recommendations"]'::jsonb),
  ('azure_native_advisor_operationalexcellence', 'RightSizing', 'Azure Advisor: Operational Excellence Recommendation', 'Azure Advisor has identified an opportunity to improve operational practices. This may include enabling diagnostics, updating configurations, or other operational improvements.', 'AzureAdvisor', '["Review and implement the Azure Advisor operational excellence recommendation."]'::jsonb, '["Follow the specific remediation steps provided in the Azure Advisor recommendation details."]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/advisor/advisor-operational-excellence-recommendations"]'::jsonb),
  ('azure_native_advisor_performance', 'RightSizing', 'Azure Advisor: Performance Recommendation', 'Azure Advisor has identified an opportunity to improve performance. This may include right-sizing resources, enabling caching, optimizing queries, or other performance improvements.', 'AzureAdvisor', '["Review and implement the Azure Advisor performance recommendation."]'::jsonb, '["Follow the specific remediation steps provided in the Azure Advisor recommendation details."]'::jsonb, '[]'::jsonb, '["https://learn.microsoft.com/en-us/azure/advisor/advisor-performance-recommendations"]'::jsonb),
  ('azure_app_service_plan_optimization', 'RightSizing', 'Azure App Service Plan Should Be Optimized', 'The App Service Plan may be over-provisioned for the current workload. Consider scaling down or using a more cost-effective tier.', 'AppService', '["The App Service Plan may be over-provisioned for the current workload. Consider scaling down or using a more cost-effective tier."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["APRA", "MAS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/app-service/overview-hosting-plans"]'::jsonb),
  ('azure_files_large_quota', 'RightSizing', 'Azure Files Share Has Very Large Quota', 'The file share has an unusually large quota that may be over-provisioned.', 'AzureFiles', '["The file share has an unusually large quota that may be over-provisioned."]'::jsonb, '["Review and remediate this finding. Refer to the documentation link below for detailed steps."]'::jsonb, '["APRA", "MAS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/storage/files/storage-files-planning"]'::jsonb),
  ('azure_vm_idle_instance', 'RightSizing', 'Azure VM Is Idle and Should Be Stopped or Deallocated', 'This Azure Virtual Machine has been identified as idle based on low CPU utilization and minimal network activity over a sustained period. Idle VMs continue to incur compute charges even when not performing useful work.', 'VirtualMachines', '["Review the VM''s workload and determine if it is still needed. If the VM is no longer required, deallocate or delete it. If the workload is intermittent, consider using Azure Auto-Shutdown or scaling down to a smaller VM size."]'::jsonb, '["Deallocate the idle VM to stop incurring compute charges:\n\\", "\\", "\\", "\n\nOr configure auto-shutdown to automatically deallocate during off-hours:\n\\", "\\", "\\", ""]'::jsonb, '["APRA", "MAS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/states-billing"]'::jsonb),
  ('azure_vm_premium_ssd_os_disk_used', 'RightSizing', 'Azure VM Using Premium SSD OS Disk May Be Over-Provisioned', 'This VM is using a Premium SSD for the OS disk. For workloads that don''t require high IOPS or low latency for the OS disk, switching to Standard SSD can reduce costs while maintaining adequate performance.', 'VirtualMachines', '["Evaluate whether the OS disk requires Premium SSD performance. For most general-purpose workloads, Standard SSD provides sufficient performance at a lower cost."]'::jsonb, '["Convert the OS disk from Premium SSD to Standard SSD:\n\\", "\\", "\\", ""]'::jsonb, '["APRA", "MAS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/disks-types"]'::jsonb),
  ('azure_vm_underutilized', 'RightSizing', 'Azure VM Is Underutilized and Should Be Right-Sized', 'This Azure Virtual Machine is consistently using a small fraction of its allocated CPU and memory resources. Right-sizing to a smaller VM SKU can significantly reduce costs while maintaining adequate performance for the workload.', 'VirtualMachines', '["Analyze the VM''s resource utilization metrics and resize to a smaller VM SKU that matches the actual workload requirements. Consider the Bs-series for burstable workloads or a smaller size within the same family."]'::jsonb, '["Resize the VM to a smaller SKU:\n\\", "\\", "\\", "\n\nNote: The VM will be restarted during the resize operation. Plan for a brief downtime window."]'::jsonb, '["APRA", "MAS"]'::jsonb, '["https://learn.microsoft.com/en-us/azure/virtual-machines/resize-vm"]'::jsonb),
  ('gcp_compute_idle_instance', 'RightSizing', 'GCP Compute Instance Is Idle and Should Be Stopped', 'This GCP Compute Engine instance has been identified as idle based on consistently low CPU utilization and minimal network activity. Idle instances continue to incur compute and licensing charges.', 'ComputeEngine', '["Review the instance''s workload and stop or delete it if no longer needed. Consider scheduling start/stop for intermittent workloads."]'::jsonb, '["Stop the idle instance:\n\\", "\\", "\\", "\n\nOr set up an instance schedule for automatic start/stop:\n\\", "\\", "\\", ""]'::jsonb, '["APRA", "MAS"]'::jsonb, '["https://cloud.google.com/compute/docs/instances/stop-start-instance"]'::jsonb),
  ('gcp_compute_underutilized', 'RightSizing', 'GCP Compute Instance Is Underutilized and Should Be Right-Sized', 'This GCP Compute Engine instance is consistently using a small fraction of its allocated CPU and memory resources. Right-sizing to a smaller machine type can reduce costs while maintaining adequate performance.', 'ComputeEngine', '["Analyze the instance''s resource utilization and resize to a smaller machine type that matches actual workload requirements."]'::jsonb, '["Resize the instance to a smaller machine type:\n\\", "\\", "\\", ""]'::jsonb, '["APRA", "MAS"]'::jsonb, '["https://cloud.google.com/compute/docs/instances/changing-machine-type-of-stopped-instance"]'::jsonb)
